/**
 * @brief 创建一个空的用户页表（仅分配根页表页）
 * @param 无
 * @return 成功返回页表指针，失败返回 NULL
 */
pagetable_t uvmcreate(void)
{
	pagetable_t pt = pagetable_create();
	if (pt == NULL)
		return NULL;

	return pt;
}

/**
 * @brief 在用户页表中分配连续的物理页并建立映射
 *        仅在 oldsz 到 newsz 之间的新页上分配物理页
 * @param pt 用户页表
 * @param oldsz 原虚拟地址上限（页对齐）
 * @param newsz 新虚拟地址上限
 * @return 成功返回 newsz，失败返回 0
 */
uintptr_t uvmalloc(pagetable_t pt, uintptr_t oldsz, uintptr_t newsz)
{
	uintptr_t a;
	uintptr_t pa;

	if (newsz > USER_TOP || oldsz > newsz)
		return 0;

	oldsz = PAGE_ALIGN_UP(oldsz);
	newsz = PAGE_ALIGN_UP(newsz);

	for (a = oldsz; a < newsz; a += PAGE_SIZE) {
		pa = (uintptr_t)kzalloc(PAGE_SIZE);
		if (pa == 0)
			goto err;
		if (mappages(pt, a, pa, 1, PTE_R | PTE_W | PTE_X | PTE_U) != 0) {
			kfree((void *)pa);
			goto err;
		}
	}
	return newsz;

err:
	uvmdealloc(pt, a, oldsz);
	return 0;
}

/**
 * @brief 解除 [newsz, oldsz) 范围的映射并释放物理页
 * @param pt 用户页表
 * @param oldsz 原虚拟地址上限
 * @param newsz 新虚拟地址上限（更小）
 * @return 返回 newsz
 */
uintptr_t uvmdealloc(pagetable_t pt, uintptr_t oldsz, uintptr_t newsz)
{
	uintptr_t a;
	uintptr_t pa;

	if (newsz >= oldsz)
		return oldsz;

	oldsz = PAGE_ALIGN_UP(oldsz);
	newsz = PAGE_ALIGN_UP(newsz);

	for (a = newsz; a < oldsz; a += PAGE_SIZE) {
		pa = walkaddr(pt, a);
		if (pa == 0)
			continue;
		unmappages(pt, a, 1);
		kfree((void *)pa);
	}
	return newsz;
}

/**
 * @brief 释放整个用户地址空间：解除所有映射，释放物理页，销毁页表
 * @param pt 用户页表
 * @param sz 用户地址空间大小（需映射的最大 VA）
 * @return 无返回值
 */
void uvmfree(pagetable_t pt, uintptr_t sz)
{
	if (pt == NULL || pt == kpagetable)
		return;

	uvmdealloc(pt, sz, 0);
	pagetable_destroy(pt);
}

/**
 * @brief 复制用户页表（用于 fork）：逐页复制映射和物理页内容
 * @param src 源用户页表
 * @param dst 目标用户页表
 * @param sz 需要复制的地址空间大小
 * @return 成功返回 0，失败返回 -1
 */
int uvmcopy(pagetable_t src, pagetable_t dst, uintptr_t sz)
{
	uintptr_t pa;
	uintptr_t va;
	pte_t *pte;
	void *mem;

	for (va = 0; va < sz; va += PAGE_SIZE) {
		if (va == TRAMPOLINE || va == TRAPFRAME)
			continue;
		pte = va2pte(src, va, false);
		if (pte == NULL || (*pte & PTE_V) == 0)
			continue;
		pa = PTE2PA(*pte);
		mem = kzalloc(PAGE_SIZE);
		if (mem == NULL)
			goto err;
		memcpy(mem, (void *)pa, PAGE_SIZE);
		if (mappages(dst, va, (uintptr_t)mem, 1,
			     PTE_FLAGS(*pte)) != 0) {
			kfree(mem);
			goto err;
		}
	}
	return 0;

err:
	uvmfree(dst, sz);
	return -1;
}

/**
 * @brief 将数据从用户空间复制到内核空间
 * @param pt 用户页表
 * @param dst 内核目标缓冲区
 * @param srcva 用户空间源地址
 * @param len 复制长度
 * @return 成功返回 0，失败返回 -1
 */
int copyin(pagetable_t pt, char *dst, uintptr_t srcva, size_t len)
{
	uintptr_t pa;
	size_t n;
	size_t offset;

	while (len > 0) {
		if (srcva >= USER_TOP)
			return -1;
		pa = walkaddr(pt, srcva);
		if (pa == 0)
			return -1;
		offset = srcva & (PAGE_SIZE - 1);
		n = PAGE_SIZE - offset;
		if (n > len)
			n = len;
		memcpy(dst, (void *)(pa + offset), n);
		dst += n;
		srcva += n;
		len -= n;
	}
	return 0;
}

/**
 * @brief 将数据从内核空间复制到用户空间
 * @param pt 用户页表
 * @param dstva 用户空间目标地址
 * @param src 内核源缓冲区
 * @param len 复制长度
 * @return 成功返回 0，失败返回 -1
 */
int copyout(pagetable_t pt, uintptr_t dstva, char *src, size_t len)
{
	uintptr_t pa;
	size_t n;
	size_t offset;

	while (len > 0) {
		if (dstva >= USER_TOP)
			return -1;
		pa = walkaddr(pt, dstva);
		if (pa == 0)
			return -1;
		offset = dstva & (PAGE_SIZE - 1);
		n = PAGE_SIZE - offset;
		if (n > len)
			n = len;
		memcpy((void *)(pa + offset), src, n);
		src += n;
		dstva += n;
		len -= n;
	}
	return 0;
}

/**
 * @brief 从用户空间复制一个以 null 结尾的字符串到内核缓冲区
 * @param pt 用户页表
 * @param dst 内核目标缓冲区
 * @param srcva 用户空间源地址
 * @param max 最大复制长度（含结尾 null）
 * @return 成功返回字符串长度，失败返回 -1
 */
int copyinstr(pagetable_t pt, char *dst, uintptr_t srcva, size_t max)
{
	uintptr_t pa;
	size_t offset;
	size_t n;
	int got_null = 0;
	char *start = dst;

	while (max > 0 && got_null == 0) {
		if (srcva >= USER_TOP)
			return -1;
		pa = walkaddr(pt, srcva);
		if (pa == 0)
			return -1;
		offset = srcva & (PAGE_SIZE - 1);
		n = PAGE_SIZE - offset;
		if (n > max)
			n = max;
		for (size_t i = 0; i < n; i++) {
			char c = *((char *)pa + offset + i);
			*dst++ = c;
			max--;
			if (c == '\0') {
				got_null = 1;
				break;
			}
		}
		srcva += n;
	}

	if (got_null)
		return dst - start - 1;
	return -1;
}

/* ============================================================
 * 页表树遍历：释放所有用户物理页 + 逐页复制（用于 execve/fork）
 *
 * 替代原来的线性扫描 [0, USER_TOP)，改为递归遍历页表树。
 * 复杂度从 O(2GB/PAGE_SIZE) 降为 O(已映射页数 + 中间页表页数)。
 *
 * RISC-V Sv39 规范：叶 PTE 至少有一个 R/W/X 位，
 * 非叶 PTE 只有 V 位（指向下一级页表页）。
 * ============================================================ */

static void uvm_free_user_pages_level(pagetable_t pt, int level, uintptr_t base)
{
	for (int i = 0; i < 512; i++) {
		pte_t pte = pt[i];
		if (!(pte & PTE_V))          /* <项目内: src/mm/pagetable.h> 跳过无效项 */
			continue;
		uintptr_t va = base | ((uintptr_t)i << PXSHIFT(level));
		if (pte & (PTE_R | PTE_W | PTE_X)) {
			/* 叶 PTE：释放物理页，跳过 trampoline/trapframe */
			if (va != TRAMPOLINE && va != TRAPFRAME) {
				kfree((void *)PTE2PA(pte));   /* <项目内: src/mm/kalloc.c> */
				pt[i] = 0;                     /* 清除 PTE 避免悬垂指针 */
			}
		} else if (level > 0) {
			/* 非叶 PTE：递归进入下一级 */
			uvm_free_user_pages_level((pagetable_t)PTE2PA(pte), level - 1, va);
		}
	}
}

void uvm_free_user_pages(pagetable_t pt)
{
	if (!pt || pt == kpagetable)
		return;
	uvm_free_user_pages_level(pt, 2, 0);
}

static int uvmcopy_tree_level(pagetable_t src, pagetable_t dst,
			       int level, uintptr_t base)
{
	for (int i = 0; i < 512; i++) {
		pte_t pte = src[i];
		if (!(pte & PTE_V))
			continue;
		uintptr_t va = base | ((uintptr_t)i << PXSHIFT(level));
		if (pte & (PTE_R | PTE_W | PTE_X)) {
			/* 叶 PTE：复制物理页到目标页表 */
			if (va == TRAMPOLINE || va == TRAPFRAME)
				continue;
			void *mem = kzalloc(PAGE_SIZE);    /* <项目内: src/mm/kalloc.c> */
			if (!mem)
				return -ENOMEM;
			memcpy(mem, (void *)PTE2PA(pte), PAGE_SIZE);  /* <string.h> */
			pte_t *dst_pte = va2pte(dst, va, true);  /* <项目内: src/mm/pagetable.c> */
			if (!dst_pte) {
				kfree(mem);
				return -ENOMEM;
			}
			*dst_pte = PA2PTE(mem) | PTE_FLAGS(pte);
		} else if (level > 0) {
			/* 非叶 PTE：递归进入下一级 */
			if (uvmcopy_tree_level((pagetable_t)PTE2PA(pte), dst,
					       level - 1, va) != 0)
				return -ENOMEM;
		}
	}
	return 0;
}

int uvmcopy_tree(pagetable_t src, pagetable_t dst)
{
	if (!src || !dst)
		return -EINVAL;
	return uvmcopy_tree_level(src, dst, 2, 0);
}

static int uvmshare_tree_level(pagetable_t src, pagetable_t dst,
			       int level, uintptr_t base)
{
	for (int i = 0; i < 512; i++) {
		pte_t pte = src[i];
		if (!(pte & PTE_V))
			continue;
		uintptr_t va = base | ((uintptr_t)i << PXSHIFT(level));
		if (pte & (PTE_R | PTE_W | PTE_X)) {
			pte_t *dst_pte;

			if (va == TRAMPOLINE || va == TRAPFRAME)
				continue;
			dst_pte = va2pte(dst, va, true);
			if (!dst_pte)
				return -ENOMEM;
			*dst_pte = pte;
		} else if (level > 0) {
			if (uvmshare_tree_level((pagetable_t)PTE2PA(pte), dst,
						level - 1, va) != 0)
				return -ENOMEM;
		}
	}
	return 0;
}

int uvmshare_tree(pagetable_t src, pagetable_t dst)
{
	if (!src || !dst)
		return -EINVAL;
	return uvmshare_tree_level(src, dst, 2, 0);
}

#include <trap/trap.h>
#include <task/sched.h>
#include <task/proc.h>
#include <misc/log.h>
#include <hal/plic.h>
#include <hal/riscv.h>
#include <hal/sbi.h>
#include <mm/pagetable.h>
#include <mm/vm.h>
#include <syscall/syscall.h>
#include <config.h>

extern void virtio_blk_isr(int irqno);
extern void virtio_net_isr(void);

extern char trampoline[], uservec[];
extern char userret[], kernelvec[];
extern bool sched_enabled;

extern void handle_timer(void);
extern void handle_external(void);
extern pagetable_t kpagetable;
extern uintptr_t sys_exit(int status);

/*
 * 处理外部中断（来自PLIC），根据中断号分发到对应设备的中断处理函数
 */
void handle_external(void)
{
	u64 hartid = r_mhartid();
	u32 irqno = plic_claim('S', hartid);

	if (irqno == 0) {
		return;
	}

	switch (irqno) {
	case 1:
		virtio_blk_isr(irqno);
		break;
	case 2:
		virtio_net_isr();
		break;
	default:
		warnf("handle_external: unknown irq %d", irqno);
		break;
	}

	plic_complete('S', hartid, irqno);
}

/*
 * 关闭中断，支持嵌套调用（第一次关闭时保存状态并屏蔽SIE，
 * 后续嵌套仅增加深度计数）
 */
void intr_off(void)
{
	struct cpu *c = thiscpu();
	if (c->intr_depth == 0) {
		// 第一次关中断：保存原始状态
		c->intr_state = r_sstatus();
		w_sstatus(c->intr_state & ~SSTATUS_SIE);
	}
	c->intr_depth++;
}

/*
 * 开启中断，支持嵌套调用（只有最外层退出时才能真正恢复中断状态）
 */
void intr_on(void)
{
	struct cpu *c = thiscpu();
	if (c->intr_depth <= 0) {
		panic("intr_on: mismatch");
	}
	c->intr_depth--;
	if (c->intr_depth == 0) {
		// 最外层退出：恢复原始中断状态
		w_sstatus(c->intr_state);
	}
}

/*
 * 恢复中断状态，强制重置中断嵌套状态（用于异常/系统调用返回等场景）
 * @param old: 要恢复的sstatus值
 */
void restore_intr(u64 old)
{
	struct cpu *c = thiscpu();
	// 强制重置嵌套状态
	c->intr_depth = 0;
	c->intr_state = old;
	w_sstatus(old);
}

/*
 * 设置内核陷阱向量为kernelvec（Direct模式）
 */
void set_kerneltrap()
{
	w_stvec((u64)kernelvec & ~0x3); // DIRECT
}

/*
 * 初始化内核陷阱处理，设置stvec、使能中断并开启SIE
 * @return: 成功返回0
 */
int trap_init()
{
	set_kerneltrap();
	w_sie(r_sie() | SIE_SEIE | SIE_STIE | SIE_SSIE);
	w_sstatus(r_sstatus() | SSTATUS_SIE | SSTATUS_FS_INIT);
	return 0;
}

/*
 * 内核陷阱/中断总入口处理函数，区分异常和中断并分发处理
 * @param ktf: 内核陷阱帧指针，包含中断/异常时保存的寄存器状态
 */
void kerneltrap(struct ktrapframe *ktf)
{
	u64 scause = ktf->scause;
	u64 sepc = ktf->sepc;
	u64 sstatus = ktf->sstatus;

	// 检查是否为中断（scause 最高位为 1）
	if ((scause & (1UL << 63)) == 0) {
		// ========== 异常（Exception）处理 ==========
		// 目前内核不应发生异常（如非法指令、缺页等）
		// 若发生，说明内核 bug
		switch (scause) {
		case InstructionAccessFault:
		case InstructionPageFault:
			panic("kernel instruction fault at %p, stval=%p",
			      sepc, r_stval());
		case IllegalInstruction:
			panic("kernel illegal instruction at %p", sepc);
		case LoadPageFault:  // load page fault
		case StorePageFault: // store/AMO page fault
			panic("kernel page fault at %p, stval=%p", sepc,
			      r_stval());
		case UserEnvCall: // environment call from U-mode (ecall)
			panic("kernel ecall at %p (should not happen)", sepc);
		default:
			panic("kernel exception: scause=%lx, sepc=%p", scause,
			      sepc);
		}
	}

	// ========== 中断（Interrupt）处理 ==========
	int irq = scause & 0x3FF; // 提取中断号（低 10 位）

	switch (irq) {
	case SupervisorSoft: // Supervisor Software Interrupt (SSI)
		// handle_ipi();
		break;

	case SupervisorTimer: // Supervisor Timer Interrupt (STI)
		handle_timer();
		break;

	case SupervisorExternal: // Supervisor External Interrupt (SEI)
		handle_external();
		break;

	default:
		panic("unknown kernel interrupt: irq=%d (scause=%lx)", irq,
		      scause);
	}

	if (sched_enabled && thiscpu()->need_resched)
		sched_yield();
}

extern char trampoline[], uservec[], userret[];

/**
 * @brief 用户态陷阱入口，处理从用户态进入内核的异常/中断
 *        由 uservec 跳转到此函数（通过 p->tf->kernel_trap 设置）
 * @param 无（通过 thiscpu()->proc->tf 访问 trapframe）
 * @return 无返回值，最终通过 usertrapret 返回用户态
 */
void usertrap(void)
{
	uintptr_t scause = r_scause();
	struct proc *p = thiscpu()->proc;

	if ((scause & (1UL << 63)) == 0) {
		switch (scause) {
		case UserEnvCall:
			p->tf->epc += 4;
			intr_on();
			syscall();
			intr_off();
			break;
		default:
			errorf("usertrap: killing process scause=%lx, "
			       "sepc=%lx stval=%lx (pid %d %s sp=%lx tp=%lx s0=%lx s1=%lx a0=%lx a1=%lx)",
			       scause, r_sepc(), r_stval(), p->pid, p->comm,
			       p->tf ? p->tf->sp : 0, p->tf ? p->tf->tp : 0,
			       p->tf ? p->tf->s0 : 0, p->tf ? p->tf->s1 : 0,
			       p->tf ? p->tf->a0 : 0, p->tf ? p->tf->a1 : 0);
			sys_exit(-1);
		}
	} else {
		int irq = scause & 0x3FF;
		switch (irq) {
		case SupervisorTimer:
			handle_timer();
			break;
		case SupervisorExternal:
			handle_external();
			break;
		default:
			break;
		}
	}
	if (thiscpu()->need_resched)
		sched_yield();
	usertrapret(thiscpu()->proc);
}

/**
 * @brief 从用户态陷阱返回，设置 stvec/sepc/sstatus 并通过跳板页的 userret 返回到用户态
 * @param p 当前进程
 * @return 无返回值（通过 userret 的 sret 回到用户态）
 */
void usertrapret(struct proc *p)
{
	intr_off();

	w_stvec(TRAMPOLINE + ((uintptr_t)uservec - (uintptr_t)trampoline));

	p->tf->kernel_satp = MAKE_SATP(kpagetable);
	p->tf->kernel_sp = (uintptr_t)p->kstack + KSTACK_SIZE;
	p->tf->kernel_trap = (uintptr_t)usertrap;
	p->tf->kernel_hartid = r_tp();

	uintptr_t sstatus = r_sstatus();
	sstatus &= ~SSTATUS_SPP;
	sstatus |= SSTATUS_SPIE;
	sstatus |= SSTATUS_FS_INIT;  /* 启用用户态 FPU */
	w_sstatus(sstatus);

	w_sepc(p->tf->epc);
	w_sscratch(TRAPFRAME);

	uintptr_t userret_addr = TRAMPOLINE +
				 ((uintptr_t)userret - (uintptr_t)trampoline);
	void (*userret_func)(uintptr_t, uintptr_t) =
		(void (*)(uintptr_t, uintptr_t))userret_addr;

	userret_func(TRAPFRAME, MAKE_SATP(p->pagetable));
}

/**
 * @brief 用户进程首次内核上下文恢复时的入口
 *        由 context_switch 切换到用户进程时执行，然后跳转到用户态
 * @param 无
 * @return 无返回值（通过 usertrapret 进入用户态，不再返回）
 */
void forkret(void)
{
	usertrapret(thiscpu()->proc);
}

#include <task/proc.h>
#include <config.h>
#include <hal/riscv.h>
#include <mm/kalloc.h>
#include <mm/pagetable.h>
#include <mm/vm.h>
#include <mm/vma.h>
#include <sync/atomic.h>
#include <misc/string.h>
#include <fs/fd_table.h>
#include <fs/vfs.h>

extern pagetable_t kpagetable;

static struct cpu cpus[CPU_NUM];
extern void idle_loop(void);
static atomic64_t next_pid = ATOMIC64_INIT(PID_MIN);

/*
 * 分配一个唯一的进程ID
 * @return: 成功返回分配的PID，失败时理论上不会失败（无限重试）
 */
pid_t alloc_pid(void)
{
	int64_t current;
	int pid;

	do {
		current = atomic64_read(&next_pid);

		if (current > PID_MAX) {
			// 理论上几乎不可能发生（需分配 21 亿次）
			// 可选择 panic、回绕或返回错误
			// 这里简单回绕到 PID_MIN
			current = atomic64_cmpxchg(&next_pid, current, PID_MIN);
			// 重试
			continue;
		}

		// 尝试将 next_pid 从 current 增加到 current+1
		int64_t new_val = current + 1;
		if (atomic64_cmpxchg(&next_pid, current, new_val) == current) {
			pid = (int)
			    current; // safe: current <= PID_MAX = INT32_MAX
			break;
		}
		// 否则重试（其他 CPU 修改了 next_pid）

	} while (1);

	return pid;
}

/*
 * 初始化指定CPU核心
 * @param id: CPU核心ID
 */
void init_cpu(u64 id)
{
	struct cpu *c = &cpus[id];
	c->need_resched = false;
	c->idle.ctx.ra = (uintptr_t)idle_loop;
	c->idle.ctx.sp = (uintptr_t)c->idle_stack + IDLE_STACK_SIZE;
	c->idle.ctx.gp = (uintptr_t)&c->idle.ktf;
	c->idle.ctx.sstatus = SSTATUS_SIE;
	c->idle.state = PROC_IDLE;
	strcpy(c->idle.comm, "idle");
	c->idle.parent = NULL;
	INIT_LIST_HEAD(&c->idle.sibling);
	c->idle.lock = SPINLOCK_INITIALIZER("idle");
	c->proc = &c->idle;
	w_gp((uintptr_t)&c->idle.ktf);
	w_tp(id);
}

/*
 * 获取当前CPU核心的cpu结构指针
 * @return: 当前CPU的cpu结构指针
 */
inline struct cpu *thiscpu() { return &cpus[r_tp()]; }

/*
 * 分配并初始化一个新的proc结构体
 * @return: 成功返回proc指针，失败返回NULL
 */
struct proc *alloc_proc()
{
	struct proc *p = kzalloc(sizeof(struct proc));
	if (!p)
		return NULL;

	p->state = PROC_UNUSED;
	p->ctx.gp = (uintptr_t)&p->ktf;
	p->ctx.sstatus = SSTATUS_SIE;
	p->nofile_cur = NR_OPEN_MAX;
	p->nofile_max = NR_OPEN_MAX;
	p->vm_owner = p;

	INIT_LIST_HEAD(&p->vma);
	INIT_LIST_HEAD(&p->runq);
	INIT_LIST_HEAD(&p->children);
	INIT_LIST_HEAD(&p->sibling);

	p->lock = (spinlock_t)SPINLOCK_INITIALIZER("proc");
	p->vm_lock = (spinlock_t)SPINLOCK_INITIALIZER("vm");

	wait_queue_init(&p->child_wait);

	p->fd_table = fd_table_alloc();
	if (!p->fd_table) {
		kfree(p);
		return NULL;
	}

	p->pwd = vfs_get_root();
	if (p->pwd) {
		dentry_get(p->pwd);
	}

	return p;
}

/*
 * 释放进程占用的所有资源
 * 调用前需确保进程不在调度队列中，且没有子进程
 * @param p: 要释放的进程结构指针
 */
void free_proc(struct proc *p)
{
	if (!p)
		return;

	if (p->parent) {
		spinlock_acquire(&p->parent->lock);
		list_del(&p->sibling);
		INIT_LIST_HEAD(&p->sibling);
		spinlock_release(&p->parent->lock);
		p->parent = NULL;
	}

	if (p->kstack)
		kfree(p->kstack);

	if (p->tf)
		kfree(p->tf);

	if (p->pagetable && p->pagetable != kpagetable) {
		if (!p->vm_shared)
			uvm_free_user_pages(p->pagetable);
		pagetable_destroy(p->pagetable);
	}

	if (p->fd_table) {
		fd_table_free(p->fd_table);
		p->fd_table = NULL;
	}

	if (p->pwd) {
		dentry_put(p->pwd);
		p->pwd = NULL;
	}

	kfree(p);
}

#include <task/sched.h>
#include <misc/list.h>
#include <misc/log.h>
#include <trap/trap.h>

struct {
	struct list_head queue;
	spinlock_t lock;
} __attribute__((aligned(CACHE_LINE_SIZE))) runq[CPU_NUM];

/*
 * 初始化所有CPU核心的运行队列
 */
void init_runq()
{
	for (int i = 0; i < CPU_NUM; i++) {
		INIT_LIST_HEAD(&runq[i].queue);
		runq[i].lock = SPINLOCK_INITIALIZER("runq");
	}
}

/*
 * 检查指定CPU核心的运行队列是否为空
 * @param hartid: CPU核心ID
 * @return: 队列为空返回true，否则返回false
 */
bool is_runq_empty(int hartid) { return list_empty(&runq[hartid].queue); }

/*
 * 将进程加入指定CPU核心的运行队列尾部
 * @param hartid: 目标CPU核心ID
 * @param p: 待入队的进程结构指针
 */
void enqueue_proc(int hartid, struct proc *p)
{
	u64 flags = r_sstatus();
	w_sstatus(flags & ~SSTATUS_SIE);
	spinlock_acquire(&runq[hartid].lock);
	list_add_tail(&p->runq, &runq[hartid].queue);
	spinlock_release(&runq[hartid].lock);
	w_sstatus(flags);
}

/*
 * 从指定CPU核心的运行队列头部取出一个进程
 * @param hartid: CPU核心ID
 * @return: 成功返回进程指针，队列为空返回NULL
 */
struct proc *dequeue_proc(int hartid)
{
	if (is_runq_empty(hartid)) {
		return NULL;
	}
	u64 flags = r_sstatus();
	w_sstatus(flags & ~SSTATUS_SIE);
	spinlock_acquire(&runq[hartid].lock);
	struct list_head *lh = runq[hartid].queue.next;
	list_del(lh);
	spinlock_release(&runq[hartid].lock);
	w_sstatus(flags);
	return container_of(lh, struct proc, runq);
}

/*
 * 主动让出CPU，触发调度切换到下一个可运行进程
 */
void sched_yield()
{
	struct cpu *c = thiscpu();
	struct proc *p = c->proc;

	u64 saved_sstatus = r_sstatus();
	w_sstatus(saved_sstatus & ~SSTATUS_SIE);

	if (p) {
		switch (p->state) {
		case PROC_RUNNING:
			p->state = PROC_RUNNABLE;
			enqueue_proc(r_tp(), p);
			break;
		default:
			break;
		}
	} else
		panic("null proc pointer in %s", __func__);

	thiscpu()->proc = NULL;
	thiscpu()->need_resched = false;
	context_switch_yield(p);

	w_sstatus(saved_sstatus);
}

/*
 * 执行上下文切换：从当前进程切换到下一个可运行进程（或idle）
 * @param old: 当前进程的结构指针
 */
void context_switch_yield(struct proc *old)
{
	struct cpu *c = thiscpu();
	struct proc *next;

	next = dequeue_proc(r_tp());
	if (!next) {
		/* 运行队列为空：如果 old 还活着就恢复它，否则走 idle */
		if (old && old->state != PROC_ZOMBIE &&
		    old->state != PROC_SLEEPING && old != &c->idle) {
			old->state = PROC_RUNNING;
			c->proc = old;
			return;
		}
		next = &c->idle;
	}

	spinlock_acquire(&next->lock);
	if (next != &c->idle) {
		next->state = PROC_RUNNING;
			}
	c->proc = next;
	spinlock_release(&next->lock);

	if (next != old)
		context_switch(&old->ctx, &next->ctx);
}

#include <sync/spinlock.h>
#include <trap/trap.h>

/*
 * 自旋锁加锁操作（关闭中断，忙等待直到获取锁）
 * @param lock: 自旋锁指针
 */
void spinlock_acquire_bare(spinlock_t *lock)
{
	assert(lock != NULL);

#ifdef SPINLOCK_DEBUG
	u64 hart = r_tp();
	if (lock->locked && lock->owner == hart)
		panic("recursive lock acquire: %s (hart %zu)", lock->name,
		      hart);
#endif

	intr_off();
	while (1) {
		if (__atomic_exchange_n(&lock->locked, 1, __ATOMIC_ACQUIRE) == 0) {
			break;
		}
		asm volatile("wfi" ::: "memory");
	}

#ifdef SPINLOCK_DEBUG
	lock->owner = r_tp();
#endif
}

/*
 * 自旋锁解锁操作（释放锁并恢复中断状态）
 * @param lock: 自旋锁指针
 */
void spinlock_release_bare(spinlock_t *lock)
{
	assert(lock != NULL);
#ifdef SPINLOCK_DEBUG
	if (!lock->locked) {
		panic("release unlocked lock: %s", lock->name);
	}
	if (lock->owner != r_tp()) {
		panic("spinlock_release: wrong CPU");
	}
	lock->owner = (u64)-1;
#endif
	__atomic_store_n(&lock->locked, 0, __ATOMIC_RELEASE);
	intr_on();
}

/*
 * 检查当前CPU是否持有指定自旋锁
 * @param lock: 自旋锁指针
 * @return: 持有锁返回非0值，否则返回0
 */
int spinlock_holding(spinlock_t *lock)
{
	assert(lock != NULL);

#ifdef SPINLOCK_DEBUG
	u64 hart = r_tp();
	return (lock->locked && lock->owner == hart);
#else
	return lock->locked;
#endif
}

#include <sync/wait.h>
#include <task/proc.h>
#include <task/sched.h>
#include <misc/log.h>
#include <sync/barrier.h>

void wait_queue_init(struct wait_queue *wq)
{
	INIT_LIST_HEAD(&wq->list);
	wq->lock = SPINLOCK_INITIALIZER("waitq");
}

void wait_queue_sleep(struct wait_queue *wq, struct proc *p)
{
	spinlock_acquire(&wq->lock);
	list_add_tail(&p->runq, &wq->list);
	p->state = PROC_SLEEPING;
	spinlock_release(&wq->lock);

	sched_yield();
}

static int wait_queue_wakeup(struct wait_queue *wq, int nr)
{
	struct proc *waken = NULL;
	int count = 0;

	spinlock_acquire(&wq->lock);
	while (!list_empty(&wq->list)) {
		struct list_head *lh = wq->list.next;
		list_del(lh);
		struct proc *p = list_entry(lh, struct proc, runq);
		p->state = PROC_RUNNABLE;
		enqueue_proc(r_tp(), p);
		waken = p;
		count++;
		if (nr > 0 && count >= nr)
			break;
	}
	spinlock_release(&wq->lock);

	if (waken) {
		thiscpu()->need_resched = true;
	}
	return count;
}

void wait_queue_wakeup_one(struct wait_queue *wq)
{
	wait_queue_wakeup(wq, 1);
}

void wait_queue_wakeup_all(struct wait_queue *wq)
{
	wait_queue_wakeup(wq, -1);
}

int wait_queue_wakeup_n(struct wait_queue *wq, int nr)
{
	if (nr <= 0)
		return 0;
	return wait_queue_wakeup(wq, nr);
}

int wait_queue_wakeup_addr(struct wait_queue *wq, uintptr_t uaddr, int nr)
{
	struct proc *waken = NULL;
	struct list_head *pos, *n;
	int count = 0;

	if (nr <= 0)
		return 0;

	spinlock_acquire(&wq->lock);
	list_for_each_safe(pos, n, &wq->list) {
		struct proc *p = list_entry(pos, struct proc, runq);

		if (p->futex_uaddr != uaddr)
			continue;

		list_del(pos);
		p->state = PROC_RUNNABLE;
		p->futex_uaddr = 0;
		enqueue_proc(r_tp(), p);
		waken = p;
		count++;
		if (count >= nr)
			break;
	}
	spinlock_release(&wq->lock);

	if (waken)
		thiscpu()->need_resched = true;
	return count;
}

int wait_queue_count_addr(struct wait_queue *wq, uintptr_t uaddr)
{
	struct list_head *pos;
	int count = 0;

	spinlock_acquire(&wq->lock);
	list_for_each(pos, &wq->list) {
		struct proc *p = list_entry(pos, struct proc, runq);

		if (p->futex_uaddr == uaddr)
			count++;
	}
	spinlock_release(&wq->lock);
	return count;
}

/*
 * 原子地将进程挂到等待队列，然后释放外部锁再让出 CPU。
 * 调用者必须已持有 lock，本函数负责释放它。
 * 这消除了 "释放锁 → sleep" 之间的竞态窗口。
 */
void wait_queue_sleep_locked(struct wait_queue *wq, struct proc *p, void *lock)
{
	spinlock_acquire(&wq->lock);
	list_add_tail(&p->runq, &wq->list);
	p->state = PROC_SLEEPING;
	spinlock_release(&wq->lock);

	spinlock_release((spinlock_t *)lock);
	sched_yield();
}

