	struct dentry *mountpoint =
	    vfs_path_lookup(NULL, target_path, LOOKUP_FOLLOW);
	if (IS_ERR(mountpoint)) {
		return PTR_ERR(mountpoint);
	}

	if (!mountpoint->d_inode || !S_ISDIR(mountpoint->d_inode->i_mode)) {
		dentry_put(mountpoint);
		return -ENOTDIR;
