	struct super_block *sb = vfs_mount(fs_type, dev, NULL);
	if (IS_ERR(sb)) {
		dentry_put(mountpoint);
		return PTR_ERR(sb);
	}

	struct mount *mnt = kmalloc(sizeof(struct mount));
	if (!mnt) {
		vfs_umount(sb);
		dentry_put(mountpoint);
		return -ENOMEM;
	}

	struct mount *root_mnt = vfs_get_root_mount();
	if (!root_mnt) {
		kfree(mnt);
		vfs_umount(sb);
		dentry_put(mountpoint);
		return -ENOENT;
