	mnt->mnt_parent = root_mnt;
	mnt->mnt_mountpoint = mountpoint;
	mnt->mnt_root = sb->s_root;
	mnt->mnt_sb = sb;
	INIT_LIST_HEAD(&mnt->mnt_mounts);
	INIT_LIST_HEAD(&mnt->mnt_child);
