 * @param file: 待释放的file结构指针
 */
void file_free(struct file *file)
{
	if (!file) {
		return;
	}

	spinlock_acquire(&file_state.lock);
	list_del(&file->f_list);
	file_state.count--;
	spinlock_release(&file_state.lock);

	kmem_cache_free(file);
}

/*
 * 基于dentry打开一个文件
 * @param dentry: 文件对应的dentry指针
 * @param flags: 打开标志
 * @return: 成功返回file结构指针，失败返回错误指针
 */
struct file *file_open(struct dentry *dentry, u32 flags)
{
	if (!dentry || !dentry->d_inode) {
		return PTR(-ENOENT);
	}

	struct file *file = file_alloc();
	if (IS_ERR(file)) {
		return file;
	}

	file->f_dentry = dentry;
	file->f_inode = dentry->d_inode;
	file->f_flags = flags;
	file->f_op = dentry->d_inode->i_fop;

	if (S_ISDIR(dentry->d_inode->i_mode)) {
		file->f_mode = S_IFDIR;
	} else if (S_ISREG(dentry->d_inode->i_mode)) {
		file->f_mode = S_IFREG;
	}

	dentry_get(dentry);

	if (file->f_op && file->f_op->open) {
		int ret = file->f_op->open(dentry->d_inode, file);
		if (ret < 0) {
			dentry_put(dentry);
			file_free(file);
			return PTR((long)ret);
		}
	}

	return file;
}

/*
 * 关闭文件（减少引用计数，为0时释放资源并调用release回调）
 * @param file: 待关闭的file结构指针
 * @return: 成功返回0，失败返回负的错误码
 */
int file_close(struct file *file)
{
	if (!file) {
		return -EINVAL;
	}

	spinlock_acquire(&file->f_lock);
	file->f_refcnt--;

	if (file->f_refcnt == 0) {
		spinlock_release(&file->f_lock);

		if (file->f_op && file->f_op->release) {
			file->f_op->release(file->f_inode, file);
		}

		if (file->f_dentry) {
			dentry_put(file->f_dentry);
		}

		file_free(file);
		return 0;
	}

	spinlock_release(&file->f_lock);
	return 0;
}

/*
 * 从文件中读取数据
 * @param file: 文件结构指针
 * @param buf: 读取缓冲区
 * @param count: 要读取的字节数
 * @return: 成功返回实际读取的字节数，失败返回负的错误码
 */
ssize_t file_read(struct file *file, void *buf, size_t count)
{
	if (!file || !buf || count == 0) {
		return -EINVAL;
	}

	/* 管道不需要维护共享文件偏移 */
	if (file->f_mode == S_IFIFO) {
		if (!file->f_op || !file->f_op->read)
			return -ENOSYS;
		loff_t pos = 0;
		return file->f_op->read(file, buf, count, &pos);
	}

	/* 字符设备/伪文件仍然需要维护 f_pos（例如 /proc/mounts） */
	if (file->f_mode == S_IFCHR) {
		if (!file->f_op || !file->f_op->read)
			return -ENOSYS;
		spinlock_acquire(&file->f_lock);
		loff_t pos = file->f_pos;
		ssize_t ret = file->f_op->read(file, buf, count, &pos);
		if (ret > 0)
			file->f_pos = pos;
		spinlock_release(&file->f_lock);
		return ret;
	}

	if (!file->f_inode) {
		return -ENOENT;
	}

	if ((file->f_flags & O_ACCMODE) == O_WRONLY) {
		return -EACCES;
	}

	if (S_ISDIR(file->f_inode->i_mode)) {
		return -EISDIR;
	}

	if (!file->f_op || !file->f_op->read) {
		return -ENOSYS;
	}

	spinlock_acquire(&file->f_lock);

	loff_t pos = file->f_pos;
	if (pos >= file->f_inode->i_size) {
		spinlock_release(&file->f_lock);
		return 0;
	}

	if (pos + count > file->f_inode->i_size) {
		count = file->f_inode->i_size - pos;
	}

	ssize_t ret = file->f_op->read(file, buf, count, &pos);
	if (ret > 0) {
		file->f_pos = pos;
	}

	spinlock_release(&file->f_lock);
	return ret;
}

/*
 * 向文件中写入数据（支持追加模式）
 * @param file: 文件结构指针
 * @param buf: 写入数据缓冲区
 * @param count: 要写入的字节数
 * @return: 成功返回实际写入的字节数，失败返回负的错误码
 */
ssize_t file_write(struct file *file, const void *buf, size_t count)
{
	if (!file || !buf || count == 0) {
		return -EINVAL;
	}

	/* 管道不需要维护共享文件偏移 */
	if (file->f_mode == S_IFIFO) {
		if (!file->f_op || !file->f_op->write)
			return -ENOSYS;
		loff_t pos = 0;
		return file->f_op->write(file, buf, count, &pos);
	}

	if (file->f_mode == S_IFCHR) {
		if (!file->f_op || !file->f_op->write)
			return -ENOSYS;
		spinlock_acquire(&file->f_lock);
		loff_t pos = file->f_pos;
		ssize_t ret = file->f_op->write(file, buf, count, &pos);
		if (ret > 0)
			file->f_pos = pos;
		spinlock_release(&file->f_lock);
		return ret;
	}

	if (!file->f_inode) {
		return -ENOENT;
	}

	if ((file->f_flags & O_ACCMODE) == O_RDONLY) {
		return -EACCES;
	}

	if (S_ISDIR(file->f_inode->i_mode)) {
		return -EISDIR;
	}

	if (!file->f_op || !file->f_op->write) {
		return -ENOSYS;
	}

	spinlock_acquire(&file->f_lock);

	loff_t pos = file->f_pos;

	if (file->f_flags & O_APPEND) {
		pos = file->f_inode->i_size;
	}

	ssize_t ret = file->f_op->write(file, buf, count, &pos);
	if (ret > 0) {
		file->f_pos = pos;
		if (pos > file->f_inode->i_size) {
			file->f_inode->i_size = pos;
		}
	}

	spinlock_release(&file->f_lock);
	return ret;
}

/*
 * 调整文件读写位置（支持SEEK_SET/SEEK_CUR/SEEK_END）
 * @param file: 文件结构指针
 * @param offset: 偏移量
 * @param whence: 基准位置
 * @return: 成功返回新的文件位置，失败返回负的错误码
 */
loff_t file_lseek(struct file *file, loff_t offset, int whence)
{
	if (!file) {
		return -EINVAL;
	}

	if (!file->f_inode) {
		return -ENOENT;
	}

	if (S_ISDIR(file->f_inode->i_mode)) {
		return -EISDIR;
	}

	spinlock_acquire(&file->f_lock);

	loff_t new_pos;
	switch (whence) {
	case SEEK_SET:
		new_pos = offset;
		break;
	case SEEK_CUR:
		new_pos = file->f_pos + offset;
		break;
	case SEEK_END:
		new_pos = file->f_inode->i_size + offset;
		break;
	default:
		spinlock_release(&file->f_lock);
		return -EINVAL;
	}

	if (new_pos < 0) {
		spinlock_release(&file->f_lock);
		return -EINVAL;
	}

	if (file->f_op && file->f_op->llseek) {
		new_pos = file->f_op->llseek(file, offset, whence);
		if (new_pos < 0) {
			spinlock_release(&file->f_lock);
			return new_pos;
		}
	}

	file->f_pos = new_pos;
	spinlock_release(&file->f_lock);
	return new_pos;
}

/*
 * 读取目录文件中的目录项
 * @param file: 目录文件结构指针
 * @param buf: 存放目录项的缓冲区
 * @param count: 缓冲区大小
 * @return: 成功返回读取的字节数，失败返回负的错误码
 */
ssize_t file_getdents(struct file *file, struct dirent *buf, size_t count)
{
	if (!file || !buf || count == 0) {
		return -EINVAL;
	}

	if (!file->f_inode) {
		return -ENOENT;
	}

	if (!S_ISDIR(file->f_inode->i_mode)) {
		return -ENOTDIR;
	}

	if (!file->f_op || !file->f_op->readdir) {
		return -ENOSYS;
	}

	int ret = file->f_op->readdir(file, buf, count);

	return ret;
}

/*
 * 增加file结构的引用计数
 * @param file: file结构指针
 */
void file_get(struct file *file)
{
	if (!file) {
		return;
	}

	spinlock_acquire(&file->f_lock);
	file->f_refcnt++;
	spinlock_release(&file->f_lock);
}

/*
 * 减少file结构的引用计数，为0时自动关闭文件
 * @param file: file结构指针
 */
void file_put(struct file *file)
{
	if (!file) {
		return;
	}

	spinlock_acquire(&file->f_lock);
	bool last = (--file->f_refcnt == 0);
	spinlock_release(&file->f_lock);

	if (last) {
		if (file->f_op && file->f_op->release)
			file->f_op->release(file->f_inode, file);
		if (file->f_dentry)
			dentry_put(file->f_dentry);
		file_free(file);
	}
}

#include <fs/super.h>
#include <fs/vfs.h>
#include <misc/log.h>
#include <misc/errno.h>
#include <misc/complier.h>
#include <mm/kalloc.h>
#include <mm/slab.h>
#include <sync/spinlock.h>

static struct kmem_cache super_cache;

static struct {
	struct list_head super_list;
	spinlock_t lock;
	u32 count;
} super_state;

/*
 * 初始化超级块子系统（创建slab缓存和链表）
 */
void super_init(void)
{
	if (kmem_cache_init(&super_cache, "super_block",
			    sizeof(struct super_block), false) != 0) {
		panic("super_init: failed to create cache");
	}

	INIT_LIST_HEAD(&super_state.super_list);
	super_state.lock = SPINLOCK_INITIALIZER("super");
	super_state.count = 0;

}

/*
 * 分配并初始化一个新的超级块
 * @param type: 所属文件系统类型
 * @param dev: 设备号
 * @return: 成功返回超级块指针，失败返回错误指针
 */
struct super_block *super_alloc(struct file_system_type *type, dev_t dev)
{
	struct super_block *sb = kmem_cache_alloc(&super_cache);
	if (!sb) {
		return PTR(-ENOMEM);
	}

	sb->s_dev = dev;
	sb->s_type = type;
	sb->s_root = NULL;
	sb->s_op = NULL;
	sb->s_fs_info = NULL;
	INIT_LIST_HEAD(&sb->s_list);
	INIT_LIST_HEAD(&sb->s_inodes);
	sb->s_lock = SPINLOCK_INITIALIZER("super_block");
	sb->s_maxbytes = 0;
	sb->s_blocksize = BLOCK_SIZE;
	sb->s_blocksize_bits = 9;
	sb->s_flags = 0;
	sb->s_count = 1;

	return sb;
}

/*
 * 释放超级块占用的内存
 * @param sb: 待释放的超级块指针
 */
void super_free(struct super_block *sb)
{
	if (!sb) {
		return;
	}

	spinlock_acquire(&super_state.lock);
	list_del(&sb->s_list);
	super_state.count--;
	spinlock_release(&super_state.lock);

	kmem_cache_free(sb);
}

/*
 * 根据设备号查找超级块
 * @param dev: 设备号
 * @return: 成功返回超级块指针，未找到返回NULL
 */
struct super_block *super_lookup(dev_t dev)
{
	spinlock_acquire(&super_state.lock);

	struct super_block *sb;
	list_for_each_entry(sb, &super_state.super_list, s_list)
	{
		if (sb->s_dev == dev) {
			spinlock_release(&super_state.lock);
			return sb;
		}
	}

	spinlock_release(&super_state.lock);
	return NULL;
}

/*
 * 增加超级块的引用计数
 * @param sb: 超级块指针
 */
void super_get(struct super_block *sb)
{
	if (!sb) {
		return;
	}

	spinlock_acquire(&sb->s_lock);
	sb->s_count++;
	spinlock_release(&sb->s_lock);
}

/*
 * 减少超级块的引用计数，引用为0时释放超级块
 * @param sb: 超级块指针
 */
void super_put(struct super_block *sb)
{
	if (!sb) {
		return;
	}

	spinlock_acquire(&sb->s_lock);
	sb->s_count--;

	if (sb->s_count == 0) {
		spinlock_release(&sb->s_lock);

		if (sb->s_op && sb->s_op->put_super) {
			sb->s_op->put_super(sb);
		}

		super_free(sb);
		return;
	}

	spinlock_release(&sb->s_lock);
}

/*
 * 注册超级块到全局链表
 * @param sb: 待注册的超级块指针
 * @return: 成功返回0，设备号重复返回-EEXIST
 */
int super_register(struct super_block *sb)
{
	if (!sb) {
		return -EINVAL;
	}

	spinlock_acquire(&super_state.lock);

	struct super_block *existing;
	list_for_each_entry(existing, &super_state.super_list, s_list)
	{
		if (existing->s_dev == sb->s_dev) {
			spinlock_release(&super_state.lock);
			return -EEXIST;
		}
	}

	list_add(&sb->s_list, &super_state.super_list);
	super_state.count++;

	spinlock_release(&super_state.lock);
	return 0;
}

/*
 * 从全局链表中注销超级块
 * @param sb: 待注销的超级块指针
 */
void super_unregister(struct super_block *sb)
{
	if (!sb) {
		return;
	}

	spinlock_acquire(&super_state.lock);
	list_del(&sb->s_list);
	super_state.count--;
	spinlock_release(&super_state.lock);
}

#include <fs/inode.h>
#include <fs/super.h>
#include <misc/log.h>
#include <misc/errno.h>
#include <misc/complier.h>
#include <misc/hashtable.h>
#include <mm/slab.h>
#include <sync/spinlock.h>

static struct kmem_cache inode_cache;

static struct {
	struct hashtable ht;
	struct list_head inode_list;
	spinlock_t lock;
	u32 count;
} inode_state;

/*
 * 初始化inode子系统（创建slab缓存和哈希表）
 */
void inode_init(void)
{
	if (kmem_cache_init(&inode_cache, "inode", sizeof(struct inode),
			    false) != 0) {
		panic("inode_init: failed to create cache");
	}

	if (hashtable_init(&inode_state.ht, 64) != 0) {
		panic("inode_init: failed to init hashtable");
	}

	INIT_LIST_HEAD(&inode_state.inode_list);
	inode_state.lock = SPINLOCK_INITIALIZER("inode");
	inode_state.count = 0;

}

/*
 * 分配并初始化一个新的inode
 * @param sb: 所属超级块指针
 * @return: 成功返回inode指针，失败返回错误指针
 */
struct inode *inode_alloc(struct super_block *sb)
{
	struct inode *inode;

	if (sb && sb->s_op && sb->s_op->alloc_inode) {
		inode = sb->s_op->alloc_inode(sb);
		if (IS_ERR(inode) || !inode) {
			return inode;
		}
	} else {
		inode = kmem_cache_alloc(&inode_cache);
		if (!inode) {
			return PTR(-ENOMEM);
		}
	}

	inode->i_ino = 0;
	inode->i_mode = 0;
	inode->i_uid = 0;
	inode->i_gid = 0;
	inode->i_size = 0;
	inode->i_blocks = 0;
	inode->i_atime = 0;
	inode->i_mtime = 0;
	inode->i_ctime = 0;
	inode->i_nlink = 1;
	inode->i_rdev = 0;

	inode->i_sb = sb;
	inode->i_op = NULL;
	inode->i_fop = NULL;
	inode->i_mapping = NULL;

	INIT_LIST_HEAD(&inode->i_list);
	INIT_LIST_HEAD(&inode->i_dentry);
	inode->i_lock = SPINLOCK_INITIALIZER("inode");
	inode->i_refcnt = 1;
	inode->i_state = I_NEW;

	return inode;
}

/*
 * 释放inode占用的内存
 * @param inode: 待释放的inode指针
 */
void inode_free(struct inode *inode)
{
	if (!inode) {
		return;
	}

	if (inode->i_sb && inode->i_sb->s_op &&
	    inode->i_sb->s_op->destroy_inode) {
		inode->i_sb->s_op->destroy_inode(inode);
		return;
	}

	spinlock_acquire(&inode_state.lock);
	hashtable_delete(&inode_state.ht, (void *)inode->i_ino);
	list_del(&inode->i_list);
	inode_state.count--;
	spinlock_release(&inode_state.lock);

	kmem_cache_free(inode);
}

/*
 * 获取指定inode号的inode（从缓存查找或新建）
 * @param sb: 超级块指针
 * @param ino: inode号
 * @return: 成功返回inode指针（引用计数已增加），失败返回错误指针
 */
struct inode *inode_get(struct super_block *sb, ino_t ino)
{
	spinlock_acquire(&inode_state.lock);

	struct inode *inode = hashtable_lookup(&inode_state.ht, (void *)ino);
	if (inode) {
		inode->i_refcnt++;
		spinlock_release(&inode_state.lock);
		return inode;
	}

	spinlock_release(&inode_state.lock);

	inode = inode_alloc(sb);
	if (IS_ERR(inode)) {
		return inode;
	}

	inode->i_ino = ino;

	spinlock_acquire(&inode_state.lock);
	hashtable_insert(&inode_state.ht, (void *)ino, inode);
	list_add(&inode->i_list, &inode_state.inode_list);
	inode_state.count++;
	spinlock_release(&inode_state.lock);

	return inode;
}

/*
 * 减少inode的引用计数，引用为0时释放inode
 * @param inode: inode指针
 */
void inode_put(struct inode *inode)
{
	if (!inode) {
		return;
	}

	spinlock_acquire(&inode->i_lock);
	inode->i_refcnt--;

	if (inode->i_refcnt == 0) {
		spinlock_release(&inode->i_lock);

		if (inode->i_sb && inode->i_sb->s_op &&
		    inode->i_sb->s_op->drop_inode) {
			if (inode->i_sb->s_op->drop_inode(inode) != 0) {
				return;
			}
		}

		inode_free(inode);
		return;
	}

	spinlock_release(&inode->i_lock);
}

/*
 * 根据inode号在全局哈希表中查找inode（不增加引用计数）
 * @param ino: inode号
 * @return: 成功返回inode指针，未找到返回NULL
 */
struct inode *inode_lookup(ino_t ino)
{
	spinlock_acquire(&inode_state.lock);
	struct inode *inode = hashtable_lookup(&inode_state.ht, (void *)ino);
	spinlock_release(&inode_state.lock);
	return inode;
}

/*
 * 标记inode为脏（数据已修改待写回）
 * @param inode: inode指针
 */
void inode_dirty(struct inode *inode)
{
	if (!inode) {
		return;
	}

	spinlock_acquire(&inode->i_lock);
	inode->i_state |= I_DIRTY;

	if (inode->i_sb && inode->i_sb->s_op &&
	    inode->i_sb->s_op->dirty_inode) {
		inode->i_sb->s_op->dirty_inode(inode);
	}

	spinlock_release(&inode->i_lock);
}

/*
 * 将脏inode写回到磁盘
 * @param inode: inode指针
 * @return: 成功返回0，失败返回负的错误码
 */
int inode_write(struct inode *inode)
{
	if (!inode) {
		return -EINVAL;
	}

	spinlock_acquire(&inode->i_lock);

	if (!(inode->i_state & I_DIRTY)) {
		spinlock_release(&inode->i_lock);
		return 0;
	}

	if (!inode->i_sb || !inode->i_sb->s_op ||
	    !inode->i_sb->s_op->write_inode) {
		spinlock_release(&inode->i_lock);
		return -ENOSYS;
	}

	int ret = inode->i_sb->s_op->write_inode(inode);
	if (ret == 0) {
		inode->i_state &= ~I_DIRTY;
	}

	spinlock_release(&inode->i_lock);
	return ret;
}

/*
 * 截断inode数据（清空大小和块数，标记为脏）
 * @param inode: inode指针
 */
void inode_truncate(struct inode *inode)
{
	if (!inode) {
		return;
	}

	spinlock_acquire(&inode->i_lock);
	inode->i_size = 0;
	inode->i_blocks = 0;
	inode_dirty(inode);
	spinlock_release(&inode->i_lock);
}

#include <fs/dentry.h>
#include <fs/inode.h>
#include <fs/super.h>
#include <misc/log.h>
#include <misc/errno.h>
#include <misc/complier.h>
#include <misc/string.h>
#include <misc/hashtable.h>
#include <mm/slab.h>
#include <mm/kalloc.h>
#include <sync/spinlock.h>

static struct kmem_cache dentry_cache;

static struct {
	struct hashtable ht;
	struct list_head dentry_list;
	struct list_head dentry_lru;
	spinlock_t lock;
	u32 count;
} dentry_state;

/*
 * 计算dentry在哈希表中的键值
 * @param sb: 超级块指针
 * @param parent: 父dentry指针
 * @param name: 文件名qstr结构
 * @return: 哈希桶索引
 */
static u32 dentry_hash_key(struct super_block *sb, struct dentry *parent,
			   struct qstr *name)
{
	u32 hash = (u32)((uintptr_t)sb ^ (uintptr_t)parent);
	hash = hash ^ name->hash;
	return hash_ptr((void *)(uintptr_t)hash, dentry_state.ht.size);
}

/*
 * 初始化dentry子系统（创建slab缓存和哈希表）
 */
void dentry_init(void)
{
	if (kmem_cache_init(&dentry_cache, "dentry", sizeof(struct dentry),
			    false) != 0) {
		panic("dentry_init: failed to create cache");
	}

	if (hashtable_init(&dentry_state.ht, 128) != 0) {
		panic("dentry_init: failed to init hashtable");
	}

	INIT_LIST_HEAD(&dentry_state.dentry_list);
	INIT_LIST_HEAD(&dentry_state.dentry_lru);
	dentry_state.lock = SPINLOCK_INITIALIZER("dentry");
	dentry_state.count = 0;

}

/*
 * 分配并初始化一个新的dentry
 * @param parent: 父dentry指针（可为NULL）
 * @param sb: 超级块指针
 * @param name: 文件名
 * @return: 成功返回dentry指针，失败返回错误指针
 */
struct dentry *dentry_alloc(struct dentry *parent, struct super_block *sb,
			    const char *name)
{
	struct dentry *dentry = kmem_cache_alloc(&dentry_cache);
	if (!dentry) {
		return PTR(-ENOMEM);
	}

	char *name_copy = kmalloc(strlen(name) + 1);
	if (!name_copy) {
		kmem_cache_free(dentry);
		return PTR(-ENOMEM);
	}
	strcpy(name_copy, name);

	dentry->d_name.name = name_copy;
	dentry->d_name.len = strlen(name);
	dentry->d_name.hash = hash_string(name, dentry->d_name.len);

	dentry->d_inode = NULL;
	dentry->d_sb = sb;
	dentry->d_parent = parent ? parent : dentry;
	dentry->d_op = NULL;
	dentry->d_fsdata = NULL;

	INIT_LIST_HEAD(&dentry->d_children);
	INIT_LIST_HEAD(&dentry->d_sibling);
	INIT_LIST_HEAD(&dentry->d_lru);
	INIT_LIST_HEAD(&dentry->d_hash);
	INIT_LIST_HEAD(&dentry->d_list);
	dentry->d_lock = SPINLOCK_INITIALIZER("dentry");
	dentry->d_refcnt = 1;
	dentry->d_flags = 0;

	if (parent) {
		spinlock_acquire(&parent->d_lock);
		list_add(&dentry->d_sibling, &parent->d_children);
		spinlock_release(&parent->d_lock);
	}

	return dentry;
}

/*
 * 释放dentry占用的所有资源
 * @param dentry: 待释放的dentry指针
 */
void dentry_free(struct dentry *dentry)
{
	if (!dentry) {
		return;
	}

	if (dentry->d_op && dentry->d_op->d_release) {
		dentry->d_op->d_release(dentry);
	}

	spinlock_acquire(&dentry_state.lock);
	if (!(dentry->d_flags & DCACHE_UNHASHED)) {
		hashtable_delete(&dentry_state.ht,
				 (void *)(uintptr_t)dentry_hash_key(
				     dentry->d_sb, dentry->d_parent, &dentry->d_name));
		if (!list_empty(&dentry->d_list)) {
			list_del(&dentry->d_list);
			INIT_LIST_HEAD(&dentry->d_list);
		}
		dentry->d_flags |= DCACHE_UNHASHED;
		dentry_state.count--;
	}
	if (!list_empty(&dentry->d_lru)) {
		list_del(&dentry->d_lru);
		INIT_LIST_HEAD(&dentry->d_lru);
	}
	spinlock_release(&dentry_state.lock);

	if (dentry->d_parent && dentry->d_parent != dentry) {
		spinlock_acquire(&dentry->d_parent->d_lock);
		if (!list_empty(&dentry->d_sibling)) {
			list_del(&dentry->d_sibling);
			INIT_LIST_HEAD(&dentry->d_sibling);
		}
		spinlock_release(&dentry->d_parent->d_lock);
	}

	if (dentry->d_inode) {
		inode_put(dentry->d_inode);
	}

	if (dentry->d_name.name) {
		kfree(dentry->d_name.name);
	}

	kmem_cache_free(dentry);
}

/*
 * 在dentry哈希表中查找指定的dentry
 * @param sb: 超级块指针
 * @param parent: 父dentry指针
 * @param name: 待查找的文件名
 * @return: 成功返回dentry指针，未找到返回NULL
 */
struct dentry *dentry_lookup(struct super_block *sb, struct dentry *parent,
			     struct qstr *name)
{
	spinlock_acquire(&dentry_state.lock);

	u32 bucket_idx = dentry_hash_key(sb, parent, name);

	struct hash_node *node;
	list_for_each_entry(node, &dentry_state.ht.buckets[bucket_idx], list)
	{
		struct dentry *dentry = (struct dentry *)node->value;
		if (dentry && dentry->d_sb == sb &&
		    dentry->d_parent == parent &&
		    dentry->d_name.len == name->len &&
		    strcmp(dentry->d_name.name, name->name) == 0) {
			dentry->d_refcnt++;
			spinlock_release(&dentry_state.lock);
			return dentry;
		}
	}

	spinlock_release(&dentry_state.lock);

	return NULL;
}

/*
 * 减少dentry的引用计数，引用为0时将dentry加入LRU链表
 * @param dentry: dentry指针
 */
void dentry_put(struct dentry *dentry)
{
	if (!dentry) {
		return;
	}

	spinlock_acquire(&dentry->d_lock);
	dentry->d_refcnt--;

	if (dentry->d_refcnt == 0) {
		spinlock_release(&dentry->d_lock);

		if (dentry->d_flags & DCACHE_UNHASHED) {
			dentry_free(dentry);
			return;
		}

		spinlock_acquire(&dentry_state.lock);
		if (list_empty(&dentry->d_lru))
			list_add(&dentry->d_lru, &dentry_state.dentry_lru);
		spinlock_release(&dentry_state.lock);
		return;
	}

	spinlock_release(&dentry->d_lock);
}

/*
 * 增加dentry的引用计数
 * @param dentry: dentry指针
 */
void dentry_get(struct dentry *dentry)
{
	if (!dentry) {
		return;
	}

	spinlock_acquire(&dentry->d_lock);
	dentry->d_refcnt++;
	spinlock_release(&dentry->d_lock);
}

/*
 * 将dentry插入全局哈希表
 * @param dentry: 待插入的dentry指针
 * @return: 成功返回0，已存在返回-EEXIST，参数错误返回-EINVAL
 */
int dentry_insert(struct dentry *dentry)
{
	if (!dentry) {
		tracef("dentry_insert: dentry is NULL");
		return -EINVAL;
	}

	tracef("dentry_insert: dentry=%p, d_sb=%p, d_parent=%p, d_name=%s",
	       dentry, dentry->d_sb, dentry->d_parent,
	       dentry->d_name.name ? dentry->d_name.name : "(null)");

	if (!dentry->d_sb) {
		tracef("dentry_insert: d_sb is NULL for dentry %p", dentry);
		return -EINVAL;
	}

	if (!dentry->d_parent) {
		tracef("dentry_insert: d_parent is NULL for dentry %p", dentry);
		return -EINVAL;
	}

	spinlock_acquire(&dentry_state.lock);

	u32 key =
	    dentry_hash_key(dentry->d_sb, dentry->d_parent, &dentry->d_name);
	/* 遍历哈希桶内链表做完整比较，避免桶索引碰撞误判为 EEXIST */
	u32 bucket_idx = hash_ptr((void *)(uintptr_t)key, dentry_state.ht.size);
	struct hash_node *node;
	list_for_each_entry(node, &dentry_state.ht.buckets[bucket_idx], list)
	{
		struct dentry *existing = (struct dentry *)node->value;
		if (existing && existing->d_sb == dentry->d_sb &&
		    existing->d_parent == dentry->d_parent &&
		    existing->d_name.len == dentry->d_name.len &&
		    strcmp(existing->d_name.name, dentry->d_name.name) == 0) {
			spinlock_release(&dentry_state.lock);
			return -EEXIST;
		}
	}

	hashtable_insert(&dentry_state.ht, (void *)(uintptr_t)key, dentry);
	list_add(&dentry->d_list, &dentry_state.dentry_list);
	dentry_state.count++;

	spinlock_release(&dentry_state.lock);
	return 0;
}

/*
 * 删除dentry（调用d_op->d_delete后释放dentry）
 * @param dentry: 待删除的dentry指针
 */
void dentry_delete(struct dentry *dentry)
{
	if (!dentry) {
		return;
	}

	if (dentry->d_op && dentry->d_op->d_delete) {
		if (dentry->d_op->d_delete(dentry) != 0) {
			return;
		}
	}

	spinlock_acquire(&dentry_state.lock);
	if (!(dentry->d_flags & DCACHE_UNHASHED)) {
		hashtable_delete(&dentry_state.ht,
				 (void *)(uintptr_t)dentry_hash_key(
				     dentry->d_sb, dentry->d_parent, &dentry->d_name));
		if (!list_empty(&dentry->d_list)) {
			list_del(&dentry->d_list);
			INIT_LIST_HEAD(&dentry->d_list);
		}
		dentry->d_flags |= DCACHE_UNHASHED;
		dentry_state.count--;
	}
	if (!list_empty(&dentry->d_lru)) {
		list_del(&dentry->d_lru);
		INIT_LIST_HEAD(&dentry->d_lru);
	}
	spinlock_release(&dentry_state.lock);

	if (dentry->d_parent && dentry->d_parent != dentry) {
		spinlock_acquire(&dentry->d_parent->d_lock);
		if (!list_empty(&dentry->d_sibling))
			list_del(&dentry->d_sibling);
		INIT_LIST_HEAD(&dentry->d_sibling);
		spinlock_release(&dentry->d_parent->d_lock);
	}

	dentry_put(dentry);
}

