	struct wait_queue *to = futex_bucket(uaddr2);
	struct proc *waken = NULL;
	struct list_head *pos, *n;
	int count = 0;
	int moved = 0;

	if (wake_nr < 0)
		wake_nr = 0;
	if (requeue_nr < 0)
		requeue_nr = 0;

