static void virtio_net_fill_rx(struct virtio_net_device *dev)
{
	struct virtq *vq = dev->vdev.vqs[0];
	int count = 0;

	for (int i = 0; i < VIRTQ_SIZE; i++) {
		void *buf = kzalloc(VIRTIO_NET_BUF_SIZE);
		if (!buf)
			break;

		dev->rx_bufs[i] = buf;

		struct virtq_buf out_bufs[1] = {
		    { .addr = buf, .len = VIRTIO_NET_BUF_SIZE }
		};

		if (virtq_add_buf(vq, NULL, 0, out_bufs, 1,
				  (void *)(uintptr_t)i) < 0) {
			kfree(buf);
			dev->rx_bufs[i] = NULL;
			break;
		}
		count++;
	}

	virtq_kick(vq);
}

static int virtio_net_init_one(uintptr_t mmio_addr, u32 irqno)
{
	struct virtio_mmio_regs *regs = (void *)mmio_addr;

	if (virtio_mmio_probe(regs, irqno) < 0)
		return -1;

	u32 device_id = mmio_read32(&regs->device_id);
	if (device_id != VIRTIO_DEVICE_TYPE_NET) {
		warnf("virtio_net_init: not a net device at %p, id=%d",
		      (void *)mmio_addr, device_id);
		return -1;
	}

	struct virtio_net_device *dev = kzalloc(sizeof(*dev));
	if (!dev) {
		errorf("virtio_net_init: failed to allocate device");
		return -1;
	}

	dev->vdev.regs = regs;
	dev->vdev.irqno = irqno;
	dev->vdev.lock = SPINLOCK_INITIALIZER("virtio_net");
	dev->vdev.polling_mode = true;

	if (virtio_mmio_init(&dev->vdev) < 0) {
		kfree(dev);
		return -1;
	}

	u32 required = 0;
	u32 rejected = VIRTIO_NET_F_CSUM | VIRTIO_F_ANY_LAYOUT |
		       VIRTIO_RING_F_INDIRECT_DESC | VIRTIO_RING_F_EVENT_IDX;

	if (virtio_negotiate_features(&dev->vdev, required, rejected) < 0) {
		kfree(dev);
		return -1;
	}

	/* receiveq (queue 0) + transmitq (queue 1) */
	if (virtio_setup_vq(&dev->vdev, 0, VIRTQ_SIZE) < 0) {
		kfree(dev);
		return -1;
	}
	if (virtio_setup_vq(&dev->vdev, 1, VIRTQ_SIZE) < 0) {
		kfree(dev);
		return -1;
	}

	/* 读取 MAC 地址（config 偏移 0-5） */
	u32 mac0 = virtio_read_config(&dev->vdev, 0);
	u32 mac1 = virtio_read_config(&dev->vdev, 4);
	dev->mac[0] = mac0 & 0xff;
	dev->mac[1] = (mac0 >> 8) & 0xff;
	dev->mac[2] = (mac0 >> 16) & 0xff;
	dev->mac[3] = (mac0 >> 24) & 0xff;
	dev->mac[4] = mac1 & 0xff;
	dev->mac[5] = (mac1 >> 8) & 0xff;

	virtio_set_status(&dev->vdev,
			  virtio_get_status(&dev->vdev) |
			      VIRTIO_CONFIG_S_DRIVER_OK);

	virtio_net_fill_rx(dev);

	net_dev = dev;

	return 0;
}

int virtio_net_init(void)
{
	struct virtio_mmio_raw slots[] = {
		VIRTIO_MMIO_0, VIRTIO_MMIO_1, VIRTIO_MMIO_2,
		VIRTIO_MMIO_3, VIRTIO_MMIO_4, VIRTIO_MMIO_5,
		VIRTIO_MMIO_6, VIRTIO_MMIO_7,
	};

	for (int i = 0; i < 8; i++) {
		struct virtio_mmio_regs *regs = (void *)slots[i].addr;
		u32 magic = mmio_read32(&regs->magic_value);

		if (magic != 0x74726976)
			continue;

		u32 device_id = mmio_read32(&regs->device_id);
		if (device_id == 0)
			continue;

		if (device_id == VIRTIO_DEVICE_TYPE_NET) {
			if (virtio_net_init_one(slots[i].addr, slots[i].irqno) == 0)
				return 0;
		}
	}

	warnf("virtio_net_init: no net device found");
	return -1;
}

int virtio_net_get_mac(u8 mac[6])
{
	if (!net_dev)
		return -1;

	memcpy(mac, net_dev->mac, 6);
	return 0;
}

int virtio_net_send(const void *data, int len)
{
	if (!net_dev)
		return -1;

	struct virtq *vq = net_dev->vdev.vqs[1];
	if (!vq)
		return -1;

	if (len > 1600 || len <= 0)
		return -1;

	int total = VIRTIO_NET_HDR_SIZE + len;
	void *buf = kzalloc(total);
	if (!buf)
		return -1;

	/* net_hdr 全零（无 offload） */
	memcpy((u8 *)buf + VIRTIO_NET_HDR_SIZE, data, len);

	struct virtio_net_tx_req *req = kzalloc(sizeof(*req));
	if (!req) {
		kfree(buf);
		return -1;
	}
	req->buf = buf;
	req->completed = false;

	struct virtq_buf in_bufs[1] = {
	    { .addr = buf, .len = total }
	};

	if (virtq_add_buf(vq, in_bufs, 1, NULL, 0, req) < 0) {
		kfree(buf);
		kfree(req);
		return -1;
	}

	virtq_kick(vq);

	while (!req->completed) {
		if (virtq_has_buf(vq)) {
			u32 done_len;
			struct virtio_net_tx_req *done = virtq_get_buf(vq, &done_len);
			if (done)
				done->completed = true;
		}
	}

	kfree(buf);
	kfree(req);
	return len;
}

int virtio_net_recv(void *buf, int buf_len)
{
	if (!net_dev)
		return -1;

	struct virtq *vq = net_dev->vdev.vqs[0];
	if (!vq)
		return -1;

	if (!virtq_has_buf(vq))
		return -1;

	u32 len;
	void *token = virtq_get_buf(vq, &len);
	if (!token)
		return -1;

	int idx = (int)(uintptr_t)token;
	void *rx_buf = net_dev->rx_bufs[idx];

	int pkt_len = len - VIRTIO_NET_HDR_SIZE;
	if (pkt_len <= 0)
		pkt_len = 0;
	if (pkt_len > buf_len)
		pkt_len = buf_len;

	if (pkt_len > 0)
		memcpy(buf, (u8 *)rx_buf + VIRTIO_NET_HDR_SIZE, pkt_len);

	/* 立即重新提交 buffer 到 receiveq */
	struct virtq_buf out_bufs[1] = {
	    { .addr = rx_buf, .len = VIRTIO_NET_BUF_SIZE }
	};

	if (virtq_add_buf(vq, NULL, 0, out_bufs, 1,
			  (void *)(uintptr_t)idx) < 0) {
		warnf("virtio_net_recv: failed to re-add rx buffer");
	}

	virtq_kick(vq);

	return pkt_len;
}

void virtio_net_isr(void)
{
	if (!net_dev)
		return;

	virtio_irq_handler(&net_dev->vdev);

	/* TX: 标记完成的请求 */
	struct virtq *txq = net_dev->vdev.vqs[1];
	if (txq) {
		while (virtq_has_buf(txq)) {
			u32 len;
			struct virtio_net_tx_req *req =
			    virtq_get_buf(txq, &len);
			if (req)
				req->completed = true;
		}
	}
}

#include <hal/virtio.h>
#include <mm/kalloc.h>
#include <mm/pm.h>
#include <misc/string.h>
#include <misc/log.h>
#include <sync/barrier.h>
#include <hal/riscv.h>

/*
 * 将虚拟地址转换为物理地址（直接身份映射）
 * @param va: 虚拟地址指针
 * @return: 对应的物理地址
 */
static inline uintptr_t va2pa(void *va) { return (uintptr_t)va; }

/*
 * 创建并初始化一个Virtqueue虚拟队列
 * @param regs: Virtio MMIO寄存器指针
 * @param queue_idx: 队列索引
 * @param num: 描述符数量
 * @return: 成功返回virtq结构体指针，失败返回NULL
 */
struct virtq *virtq_create(struct virtio_mmio_regs *regs, u16 queue_idx,
			   u16 num)
{
	size_t size = vring_size(num);
	size = ALIGN_UP(size, PAGE_SIZE);

	void *mem = kmalloc(size);
	if (!mem) {
		errorf("virtq_create: failed to allocate memory");
		return NULL;
	}
	memset(mem, 0, size);

	struct virtq *vq = kmalloc(sizeof(struct virtq));
	if (!vq) {
		kfree(mem);
		errorf("virtq_create: failed to allocate virtq struct");
		return NULL;
	}

	vq->regs = regs;
	vq->queue_idx = queue_idx;
	vq->num = num;
	vq->num_free = num;
	vq->free_head = 0;
	vq->avail_idx = 0;
	vq->used_idx = 0;
	vq->lock = SPINLOCK_INITIALIZER("virtq");

	for (int i = 0; i < VIRTQ_SIZE; i++) {
		vq->data[i] = NULL;
	}

	uintptr_t pa = va2pa(mem);
	vq->descs = (struct virtq_desc *)mem;

	/* QEMU legacy formula: avail = desc + num*sizeof(desc), no align.
	 * used = ALIGN_UP(avail + avail_ring_size, VRING_ALIGN).
	 * Modern mode uses explicit addresses per ring register.
	 * vring_size() includes VRING_ALIGN*2 padding so both fit. */
	size_t avail_offset = sizeof(struct virtq_desc) * num;
	vq->avail = (struct virtq_avail *)((uintptr_t)mem + avail_offset);

	size_t used_offset = avail_offset + sizeof(u16) * (3 + num);
	used_offset = ALIGN_UP(used_offset, VRING_ALIGN);
	vq->used = (struct virtq_used *)((uintptr_t)mem + used_offset);

	for (int i = 0; i < num; i++) {
		vq->descs[i].addr = 0;
		vq->descs[i].len = 0;
		vq->descs[i].flags = VRING_DESC_F_NEXT;
		vq->descs[i].next = (i + 1) % num;
	}
	vq->descs[num - 1].flags = 0;
	vq->descs[num - 1].next = 0;

	vq->avail->flags = 0;
	vq->avail->idx = 0;
	vq->used->flags = 0;
	vq->used->idx = 0;

	return vq;
}

/*
 * 销毁Virtqueue，释放相关内存
 * @param vq: virtq结构体指针
 */
void virtq_destroy(struct virtq *vq)
{
	if (!vq)
		return;

	kfree(vq->descs);
	kfree(vq);
}

/*
 * 从Virtqueue的空闲链表中分配一个描述符
 * @param vq: virtq结构体指针
 * @return: 描述符索引，若无空闲描述符则返回-1(U16_MAX)
 */
static u16 virtq_alloc_desc(struct virtq *vq)
{
	if (vq->num_free == 0) {
		return -1;
	}

	u16 idx = vq->free_head;
	vq->free_head = vq->descs[idx].next;
	vq->num_free--;

	return idx;
}

/*
 * 将指定描述符释放回Virtqueue的空闲链表
 * @param vq: virtq结构体指针
 * @param idx: 描述符索引
 */
static void virtq_free_desc(struct virtq *vq, u16 idx)
{
	vq->descs[idx].addr = 0;
	vq->descs[idx].len = 0;
	vq->descs[idx].flags = VRING_DESC_F_NEXT;
	vq->descs[idx].next = vq->free_head;
	vq->free_head = idx;
	vq->num_free++;
}

/*
 * 向Virtqueue添加缓冲区描述符链（输入和输出缓冲区）
 * @param vq: virtq结构体指针
 * @param in_bufs: 输入缓冲区数组（设备写入）
 * @param n_in: 输入缓冲区数量
 * @param out_bufs: 输出缓冲区数组（设备读取）
 * @param n_out: 输出缓冲区数量
 * @param token: 与该请求关联的令牌指针
 * @return: 成功返回描述符链头部索引，失败返回-1
 */
int virtq_add_buf(struct virtq *vq, struct virtq_buf *in_bufs, int n_in,
		  struct virtq_buf *out_bufs, int n_out, void *token)
{
	spinlock_acquire(&vq->lock);

	int total = n_in + n_out;
	if (total > vq->num_free) {
		spinlock_release(&vq->lock);
		return -1;
	}

	u16 head = virtq_alloc_desc(vq);
	u16 prev = head;
	vq->data[head] = token;

	for (int i = 0; i < n_in; i++) {
		vq->descs[prev].addr = va2pa(in_bufs[i].addr);
		vq->descs[prev].len = in_bufs[i].len;
		vq->descs[prev].flags = 0;

		if (i < n_in - 1 || n_out > 0) {
			u16 next = virtq_alloc_desc(vq);
			vq->descs[prev].next = next;
			vq->descs[prev].flags |= VRING_DESC_F_NEXT;
			prev = next;
		}
	}

	for (int i = 0; i < n_out; i++) {
		vq->descs[prev].addr = va2pa(out_bufs[i].addr);
		vq->descs[prev].len = out_bufs[i].len;
		vq->descs[prev].flags = VRING_DESC_F_WRITE;

		if (i < n_out - 1) {
			u16 next = virtq_alloc_desc(vq);
			vq->descs[prev].next = next;
			vq->descs[prev].flags |= VRING_DESC_F_NEXT;
			prev = next;
		}
	}

	vq->descs[prev].flags &= ~VRING_DESC_F_NEXT;
	vq->descs[prev].next = 0;

	u16 avail_idx = vq->avail_idx % vq->num;
	vq->avail->ring[avail_idx] = head;
	wmb();
	vq->avail->idx = ++vq->avail_idx;

	spinlock_release(&vq->lock);

	return head;
}

/*
 * 从Virtqueue的used ring中获取已完成的缓冲区，并释放相关描述符
 * @param vq: virtq结构体指针
 * @param len: 输出参数，写入数据的长度
 * @return: 成功返回请求的令牌指针，无已完成缓冲区返回NULL
 */
void *virtq_get_buf(struct virtq *vq, u32 *len)
{
	spinlock_acquire(&vq->lock);

	rmb();
	u16 used_idx = vq->used->idx;
	if (vq->used_idx == used_idx) {
		spinlock_release(&vq->lock);
		return NULL;
	}

	u16 idx = vq->used_idx % vq->num;
	u16 head = vq->used->ring[idx].id;
	if (len) {
		*len = vq->used->ring[idx].len;
	}

	void *token = vq->data[head];
	vq->data[head] = NULL;

	u16 next;
	while (vq->descs[head].flags & VRING_DESC_F_NEXT) {
		next = vq->descs[head].next;
		virtq_free_desc(vq, head);
		head = next;
	}
	virtq_free_desc(vq, head);

	vq->used_idx++;

	spinlock_release(&vq->lock);

	return token;
}

/*
 * 检查Virtqueue中是否有已完成的缓冲区可供获取
 * @param vq: virtq结构体指针
 * @return: 有已完成缓冲区返回true，否则返回false
 */
bool virtq_has_buf(struct virtq *vq)
{
	rmb();
	return vq->used_idx != vq->used->idx;
}

/*
 * 通知Virtio设备有新的缓冲区描述符已加入可用ring
 * @param vq: virtq结构体指针
 */
void virtq_kick(struct virtq *vq)
{
	mb();
	mmio_write32(&vq->regs->queue_notify, vq->queue_idx);
}

/*
 * 获取Virtqueue中当前正在使用的描述符数量
 * @param vq: virtq结构体指针
 * @return: 使用中的描述符数量
 */
u16 virtq_desc_count(struct virtq *vq)
{
	spinlock_acquire(&vq->lock);
	u16 count = vq->num - vq->num_free;
	spinlock_release(&vq->lock);
	return count;
}

#include "device.h"
#include <misc/log.h>
#include <sync/barrier.h>
#include <hal/plic.h>
#include <hal/riscv.h>
#include <config.h>

#define VIRTIO_MMIO_MAGIC 0x74726976

#define VIRTIO_REG_MAGIC_VALUE 0x000
#define VIRTIO_REG_VERSION 0x004
#define VIRTIO_REG_DEVICE_ID 0x008
#define VIRTIO_REG_VENDOR_ID 0x00c
#define VIRTIO_REG_DEVICE_FEATURES 0x010
#define VIRTIO_REG_DRIVER_FEATURES 0x020
#define VIRTIO_REG_QUEUE_SEL 0x030
#define VIRTIO_REG_QUEUE_NUM_MAX 0x034
#define VIRTIO_REG_QUEUE_NUM 0x038
#define VIRTIO_REG_QUEUE_ALIGN 0x03c
#define VIRTIO_REG_QUEUE_PFN 0x040
#define VIRTIO_REG_QUEUE_READY 0x044
#define VIRTIO_REG_QUEUE_NOTIFY 0x050
#define VIRTIO_REG_INT_STATUS 0x060
#define VIRTIO_REG_INT_ACK 0x064
#define VIRTIO_REG_STATUS 0x070
#define VIRTIO_REG_QUEUE_DESC_LO 0x080
#define VIRTIO_REG_QUEUE_DESC_HI 0x084
#define VIRTIO_REG_QUEUE_AVAIL_LO 0x090
#define VIRTIO_REG_QUEUE_AVAIL_HI 0x094
#define VIRTIO_REG_QUEUE_USED_LO 0x0a0
#define VIRTIO_REG_QUEUE_USED_HI 0x0a4
#define VIRTIO_REG_CONFIG_GEN 0x0fc
#define VIRTIO_REG_CONFIG 0x100

/*
 * 读取Virtio MMIO寄存器的值
 * @param dev: Virtio设备结构体指针
 * @param offset: 寄存器偏移量
 * @return: 寄存器32位值
 */
static inline u32 virtio_read_reg(struct virtio_device *dev, u32 offset)
{
	return mmio_read32((void *)((uintptr_t)dev->regs + offset));
}

/*
 * 向Virtio MMIO寄存器写入值
 * @param dev: Virtio设备结构体指针
 * @param offset: 寄存器偏移量
 * @param val: 待写入的32位值
 */
static inline void virtio_write_reg(struct virtio_device *dev, u32 offset,
				    u32 val)
{
	mmio_write32((void *)((uintptr_t)dev->regs + offset), val);
}

/*
 * 设置Virtio设备的状态寄存器
 * @param dev: Virtio设备结构体指针
 * @param status: 状态值
 */
void virtio_set_status(struct virtio_device *dev, u32 status)
{
	virtio_write_reg(dev, VIRTIO_REG_STATUS, status);
	mb();
}

/*
 * 读取Virtio设备的状态寄存器
 * @param dev: Virtio设备结构体指针
 * @return: 当前状态值
 */
u32 virtio_get_status(struct virtio_device *dev)
{
	rmb();
	return virtio_read_reg(dev, VIRTIO_REG_STATUS);
}

/*
 * 探测Virtio MMIO设备，验证Magic值和版本号
 * @param regs: Virtio MMIO寄存器指针
 * @param irqno: 中断号
 * @return: 成功返回0，失败返回-1
 */
int virtio_mmio_probe(struct virtio_mmio_regs *regs, u32 irqno)
{
	u32 magic = mmio_read32(&regs->magic_value);
	u32 version = mmio_read32(&regs->version);
	u32 device_id = mmio_read32(&regs->device_id);
	u32 vendor_id = mmio_read32(&regs->vendor_id);

	if (magic != VIRTIO_MMIO_MAGIC) {
		warnf("virtio_mmio: invalid magic %x", magic);
		return -1;
	}

	if (version != 1 && version != 2) {
		warnf("virtio_mmio: unsupported version %d", version);
		return -1;
	}

	if (device_id == 0) {
		debugf("virtio_mmio: no device at this address");
		return -1;
	}

	return 0;
}

/*
 * 初始化Virtio MMIO设备，完成ACKNOWLEDGE和DRIVER状态设置
 * @param dev: Virtio设备结构体指针
 * @return: 成功返回0，失败返回-1
 */
int virtio_mmio_init(struct virtio_device *dev)
{
	virtio_set_status(dev, 0);
	mb();

	virtio_set_status(dev, VIRTIO_CONFIG_S_ACKNOWLEDGE);
	if (!(virtio_get_status(dev) & VIRTIO_CONFIG_S_ACKNOWLEDGE)) {
		errorf("virtio_mmio_init: ACKNOWLEDGE failed");
		return -1;
	}

	virtio_set_status(dev,
			  VIRTIO_CONFIG_S_ACKNOWLEDGE | VIRTIO_CONFIG_S_DRIVER);
	if (!(virtio_get_status(dev) & VIRTIO_CONFIG_S_DRIVER)) {
		errorf("virtio_mmio_init: DRIVER failed");
		return -1;
	}

	dev->device_id = virtio_read_reg(dev, VIRTIO_REG_DEVICE_ID);
	dev->vendor_id = virtio_read_reg(dev, VIRTIO_REG_VENDOR_ID);
	dev->version = virtio_read_reg(dev, VIRTIO_REG_VERSION);

	return 0;
}

/*
 * 协商Virtio设备特性：读取设备特性，屏蔽被拒绝的特性，写入驱动特性并确认
 * @param dev: Virtio设备结构体指针
 * @param required: 强制要求的特性位掩码
 * @param rejected: 拒绝的特性位掩码（将被清除）
 * @return: 成功返回0，失败返回-1
 */
int virtio_negotiate_features(struct virtio_device *dev, u32 required,
				      u32 rejected)
{
	u32 device_features = virtio_read_reg(dev, VIRTIO_REG_DEVICE_FEATURES);

	u32 driver_features = device_features & ~rejected;
	driver_features |= required;

	virtio_write_reg(dev, VIRTIO_REG_DRIVER_FEATURES, driver_features);
	dev->negotiated_features = driver_features;

	virtio_set_status(dev,
			  virtio_get_status(dev) | VIRTIO_CONFIG_S_FEATURES_OK);
	mb();

	u32 status = virtio_get_status(dev);
	if (!(status & VIRTIO_CONFIG_S_FEATURES_OK)) {
		errorf("virtio_negotiate_features: FEATURES_OK not set");
		virtio_set_status(dev, VIRTIO_CONFIG_S_FAILED);
		return -1;
	}

	return 0;
}

/*
 * 设置Virtio设备的虚拟队列，分配描述符、avail和used ring并写入MMIO寄存器
 * @param dev: Virtio设备结构体指针
 * @param vq_idx: 队列索引
 * @param num: 队列大小（描述符数量）
 * @return: 成功返回0，失败返回-1
 */
int virtio_setup_vq(struct virtio_device *dev, u32 vq_idx, u16 num)
{
	if (vq_idx >= 8) {
		errorf("virtio_setup_vq: invalid vq_idx %d", vq_idx);
		return -1;
	}

	virtio_write_reg(dev, VIRTIO_REG_QUEUE_SEL, vq_idx);
	mb();

	u32 max = virtio_read_reg(dev, VIRTIO_REG_QUEUE_NUM_MAX);
	if (num > max)
		num = max;

	if (num == 0) {
		errorf("virtio_setup_vq: queue %d not available", vq_idx);
		return -1;
	}

	struct virtq *vq = virtq_create(dev->regs, vq_idx, num);
	if (!vq) {
		errorf("virtio_setup_vq: failed to create virtq");
		return -1;
	}

	virtio_write_reg(dev, VIRTIO_REG_QUEUE_NUM, num);
	mb();

	uintptr_t desc_pa = (uintptr_t)vq->descs;

	if (dev->version == 1) {
		/* QEMU 10.0.2 requires VIRTIO_MMIO_GUEST_PAGE_SIZE to be
		 * explicitly set; the reset default for guest_page_shift is
		 * 0, so QUEUE_PFN = addr >> 0 = addr (wrong!) instead of
		 * addr >> 12.  Older QEMU (8.x) defaulted to 12. */
		virtio_write_reg(dev, 0x028, PAGE_SIZE);
		mb();
		virtio_write_reg(dev, VIRTIO_REG_QUEUE_ALIGN, PAGE_SIZE);
		mb();
		virtio_write_reg(dev, VIRTIO_REG_QUEUE_PFN, desc_pa / PAGE_SIZE);
		mb();
	} else {
		uintptr_t avail_pa = (uintptr_t)vq->avail;
		uintptr_t used_pa = (uintptr_t)vq->used;

		virtio_write_reg(dev, VIRTIO_REG_QUEUE_DESC_LO,
				 (u32)(desc_pa & 0xffffffff));
		virtio_write_reg(dev, VIRTIO_REG_QUEUE_DESC_HI,
				 (u32)(desc_pa >> 32));
		virtio_write_reg(dev, VIRTIO_REG_QUEUE_AVAIL_LO,
				 (u32)(avail_pa & 0xffffffff));
		virtio_write_reg(dev, VIRTIO_REG_QUEUE_AVAIL_HI,
				 (u32)(avail_pa >> 32));
		virtio_write_reg(dev, VIRTIO_REG_QUEUE_USED_LO,
				 (u32)(used_pa & 0xffffffff));
		virtio_write_reg(dev, VIRTIO_REG_QUEUE_USED_HI,
				 (u32)(used_pa >> 32));
		mb();

		virtio_write_reg(dev, VIRTIO_REG_QUEUE_READY, 1);
		mb();
	}

	dev->vqs[vq_idx] = vq;
	dev->num_vqs++;

	return 0;
}

/*
 * Virtio中断处理函数，读取中断状态并应答中断
 * @param dev: Virtio设备结构体指针
 */
void virtio_irq_handler(struct virtio_device *dev)
{
	u32 status = virtio_read_reg(dev, VIRTIO_REG_INT_STATUS);

	if (status & 1) {
		debugf("virtio_irq: used buffer notification");
	}

	if (status & 2) {
		debugf("virtio_irq: configuration change");
	}

	virtio_write_reg(dev, VIRTIO_REG_INT_ACK, status);
	mb();
}

/*
 * 读取Virtio设备的配置空间（带世代号检测，防止读取到不一致数据）
 * @param dev: Virtio设备结构体指针
 * @param offset: 配置空间偏移量
 * @return: 配置值（32位）
 */
u32 virtio_read_config(struct virtio_device *dev, u32 offset)
{
	u32 old_gen, new_gen;
	u32 value;

	do {
		old_gen = virtio_read_reg(dev, VIRTIO_REG_CONFIG_GEN);
		value = virtio_read_reg(dev, VIRTIO_REG_CONFIG + offset);
		new_gen = virtio_read_reg(dev, VIRTIO_REG_CONFIG_GEN);
	} while (old_gen != new_gen);

	return value;
}

/*
 * 写入Virtio设备的配置空间
 * @param dev: Virtio设备结构体指针
 * @param offset: 配置空间偏移量
 * @param value: 待写入的32位值
 */
void virtio_write_config(struct virtio_device *dev, u32 offset, u32 value)
{
	virtio_write_reg(dev, VIRTIO_REG_CONFIG + offset, value);
	mb();
}

#include <hal/blk.h>
#include <misc/log.h>
#include <misc/string.h>
#include <mm/kalloc.h>

#define BLK_MAX_DEVICES 16

static struct {
	struct block_device *devices[BLK_MAX_DEVICES];
	u32 count;
	spinlock_t lock;
} blk_registry;

/*
 * 初始化块设备注册表，清空设备列表并初始化自旋锁
 */
void blk_init(void)
{
	blk_registry.count = 0;
	blk_registry.lock = SPINLOCK_INITIALIZER("blk_registry");
	for (int i = 0; i < BLK_MAX_DEVICES; i++) {
		blk_registry.devices[i] = NULL;
	}
}

/*
 * 注册块设备到全局设备列表
 * @param dev: 块设备结构体指针
 * @return: 成功返回0，失败返回-1（设备已满或设备号重复）
 */
int blk_register(struct block_device *dev)
{
	spinlock_acquire(&blk_registry.lock);

	if (blk_registry.count >= BLK_MAX_DEVICES) {
		spinlock_release(&blk_registry.lock);
		errorf("blk_register: too many devices");
		return -1;
	}

	u32 major = MAJOR(dev->devno);
	u32 minor = MINOR(dev->devno);

	for (int i = 0; i < blk_registry.count; i++) {
		if (blk_registry.devices[i]->devno == dev->devno) {
			spinlock_release(&blk_registry.lock);
			warnf("blk_register: device %d:%d already registered",
			      major, minor);
			return -1;
		}
	}

	blk_registry.devices[blk_registry.count++] = dev;

	spinlock_release(&blk_registry.lock);

	return 0;
}

/*
 * 根据设备号查找已注册的块设备
 * @param devno: 设备号
 * @return: 块设备结构体指针，未找到则返回NULL
 */
struct block_device *blk_lookup(dev_t devno)
{
	spinlock_acquire(&blk_registry.lock);

	for (int i = 0; i < blk_registry.count; i++) {
		if (blk_registry.devices[i]->devno == devno) {
			struct block_device *dev = blk_registry.devices[i];
			spinlock_release(&blk_registry.lock);
			return dev;
		}
	}

	spinlock_release(&blk_registry.lock);
	return NULL;
}

/*
 * 根据设备号获取块设备（blk_lookup的别名）
 * @param devno: 设备号
 * @return: 块设备结构体指针，未找到则返回NULL
 */
struct block_device *blk_get(dev_t devno) { return blk_lookup(devno); }

/*
 * 从块设备读取指定数量的扇区数据
 * @param devno: 设备号
 * @param sector: 起始扇区号
 * @param buf: 数据缓冲区
 * @param nsectors: 要读取的扇区数
 * @return: 成功返回0，失败返回-1
 */
int blk_read(dev_t devno, u64 sector, void *buf, u32 nsectors)
{
	struct block_device *dev = blk_lookup(devno);
	if (!dev) {
		errorf("blk_read: device %d:%d not found", MAJOR(devno),
		       MINOR(devno));
		return -1;
	}

	if (!dev->ops || !dev->ops->read) {
		errorf("blk_read: device %s has no read operation", dev->name);
		return -1;
	}

	spinlock_acquire(&dev->lock);
	int ret = dev->ops->read(dev, sector, buf, nsectors);
	spinlock_release(&dev->lock);

	return ret;
}

/*
 * 向块设备写入指定数量的扇区数据
 * @param devno: 设备号
 * @param sector: 起始扇区号
 * @param buf: 待写入的数据缓冲区
 * @param nsectors: 要写入的扇区数
 * @return: 成功返回0，失败返回-1
 */
int blk_write(dev_t devno, u64 sector, const void *buf, u32 nsectors)
{
	struct block_device *dev = blk_lookup(devno);
	if (!dev) {
		errorf("blk_write: device %d:%d not found", MAJOR(devno),
		       MINOR(devno));
		return -1;
	}

	if (!dev->ops || !dev->ops->write) {
		errorf("blk_write: device %s has no write operation",
		       dev->name);
		return -1;
	}

	spinlock_acquire(&dev->lock);
	int ret = dev->ops->write(dev, sector, buf, nsectors);
	spinlock_release(&dev->lock);

	return ret;
}

/*
 * 刷新块设备的写缓存
 * @param devno: 设备号
 * @return: 成功返回0，失败返回-1（设备不支持flush时返回0）
 */
int blk_flush(dev_t devno)
{
	struct block_device *dev = blk_lookup(devno);
	if (!dev) {
		return -1;
	}

	if (!dev->ops || !dev->ops->flush) {
		return 0;
	}

	spinlock_acquire(&dev->lock);
	int ret = dev->ops->flush(dev);
	spinlock_release(&dev->lock);

	return ret;
}

/*
 * 获取块设备的容量（扇区数）
 * @param devno: 设备号
 * @return: 扇区总数，失败返回0
 */
u64 blk_capacity(dev_t devno)
{
	struct block_device *dev = blk_lookup(devno);
	if (!dev || !dev->ops || !dev->ops->get_capacity) {
		return 0;
	}
	return dev->ops->get_capacity(dev);
}

/*
 * 获取块设备的块大小（字节数）
 * @param devno: 设备号
 * @return: 块大小（字节），失败返回默认BLOCK_SIZE
 */
u32 blk_block_size(dev_t devno)
{
	struct block_device *dev = blk_lookup(devno);
	if (!dev || !dev->ops || !dev->ops->get_block_size) {
		return BLOCK_SIZE;
	}
	return dev->ops->get_block_size(dev);
}

#include <hal/riscv.h>
