static long wait_with_timeout(long pid, int *status, unsigned long timeout_sec)
{
	unsigned long deadline = now_sec() + timeout_sec;
	long ret;

	for (;;) {
		ret = my_wait4(pid, status, WNOHANG, 0);
		if (ret != 0)
			return ret;
		if (now_sec() >= deadline) {
