static void shared_unmap_page_children(struct proc *node, struct proc *owner,
				       uintptr_t va)
{
	struct list_head *pos;

	if (!node)
		return;

	spinlock_acquire(&node->lock);
	list_for_each(pos, &node->children) {
		struct proc *child = list_entry(pos, struct proc, sibling);
		pte_t *pte;
		if (!child->vm_shared || shared_vm_owner(child) != owner)
			continue;
		pte = va2pte(child->pagetable, va, false);
		if (pte)
			*pte = 0;
		unmappages(child->pagetable, va, 1);
		shared_unmap_page_children(child, owner, va);
	}
	spinlock_release(&node->lock);
}

static int shared_protect_page_children(struct proc *node, struct proc *owner,
					uintptr_t va, int pte_flags)
{
	struct list_head *pos;
	int ret = 0;

	if (!node)
		return 0;

	spinlock_acquire(&node->lock);
	list_for_each(pos, &node->children) {
		struct proc *child = list_entry(pos, struct proc, sibling);
		pte_t *pte;
		if (!child->vm_shared || shared_vm_owner(child) != owner)
			continue;
		pte = va2pte(child->pagetable, va, false);
		if (!pte || !(*pte & PTE_V)) {
			ret = -ENOMEM;
			break;
		}
		*pte = PA2PTE(PTE2PA(*pte)) | pte_flags | PTE_V | PTE_A |
		       ((pte_flags & PTE_W) ? PTE_D : 0);
		ret = shared_protect_page_children(child, owner, va, pte_flags);
		if (ret != 0)
			break;
	}
	spinlock_release(&node->lock);
	return ret;
}

static int shared_reserve_page(struct proc *owner, uintptr_t va)
{
	pte_t *pte = va2pte(owner->pagetable, va, true);
	int ret;

	if (!pte)
		return -ENOMEM;
	*pte = PTE_MMAP_RESERVED;

	ret = shared_reserve_page_children(owner, owner, va);
	sfence_vma();
	return ret;
}

static void shared_unmap_page(struct proc *owner, uintptr_t va)
{
	pte_t *pte;

	pte = va2pte(owner->pagetable, va, false);
	if (pte)
		*pte = 0;
	unmappages(owner->pagetable, va, 1);
	shared_unmap_page_children(owner, owner, va);
	sfence_vma();
}

static int shared_protect_page(struct proc *owner, uintptr_t va, int pte_flags)
{
	pte_t *pte;
	bool prot_none = (pte_flags & PTE_U) == 0;

	pte = va2pte(owner->pagetable, va, false);
	if (!pte || !(*pte & PTE_V)) {
		if (!pte || !(*pte & PTE_MMAP_RESERVED))
			return -ENOMEM;
		if (prot_none)
			return 0;
		uintptr_t pa = (uintptr_t)kzalloc(PAGE_SIZE);
		if (!pa)
			return -ENOMEM;
		return shared_map_page(owner, va, pa, pte_flags);
	}
	*pte = PA2PTE(PTE2PA(*pte)) | pte_flags | PTE_V | PTE_A |
	       ((pte_flags & PTE_W) ? PTE_D : 0);

	if (shared_protect_page_children(owner, owner, va, pte_flags) != 0)
		return -ENOMEM;
	sfence_vma();
	return 0;
}

static bool user_range_has_mapping(pagetable_t pt, uintptr_t start, size_t sz)
{
	uintptr_t end = start + sz;

	for (uintptr_t a = start; a < end; a += PAGE_SIZE) {
		pte_t *pte = va2pte(pt, a, false);
		if (pte && ((*pte & PTE_V) || (*pte & PTE_MMAP_RESERVED)))
			return true;
	}
	return false;
}

static uintptr_t find_free_user_range(pagetable_t pt, uintptr_t start, size_t sz,
				      uintptr_t limit)
{
	uintptr_t cur = PAGE_ALIGN_UP(start);
	uintptr_t end_limit;

	if (sz == 0 || cur >= limit)
		return 0;
	if (sz > limit - cur)
		return 0;

	end_limit = limit - sz;
	while (cur <= end_limit) {
		if (!user_range_has_mapping(pt, cur, sz))
			return cur;
		cur += PAGE_SIZE;
	}
	return 0;
}

static struct proc *find_child_by_pid(struct proc *parent, int pid)
{
	struct list_head *pos;

	if (!parent)
		return NULL;

	list_for_each(pos, &parent->children) {
		struct proc *child = list_entry(pos, struct proc, sibling);
		if (child->pid == pid)
			return child;
	}

	return NULL;
}

static struct proc *find_related_thread(int tgid, int tid)
{
	struct proc *self = curproc();
	struct proc *target;

	if (tid <= 0)
		return NULL;
	if (tgid > 0 && tgid != self->tgid)
		return NULL;
	if (self->pid == tid)
		return self;

	target = find_child_by_pid(self, tid);
	if (target && target->tgid == self->tgid)
		return target;
	if (self->parent) {
		target = find_child_by_pid(self->parent, tid);
		if (target && target->tgid == self->tgid)
			return target;
	}
	return NULL;
}

static bool proc_has_unmasked_signal(struct proc *p)
{
	return (p->sigpending & ~p->sigmask) != 0;
}

static void proc_queue_signal(struct proc *p, int sig)
{
	if (!p || sig <= 0 || sig >= 64)
		return;
	p->sigpending |= 1ULL << (sig - 1);
	if (p->state == PROC_SLEEPING && p->futex_uaddr) {
		wait_queue_wakeup_addr(futex_bucket(p->futex_uaddr),
				       p->futex_uaddr, 1);
	}
}

static void reap_zombie_threads(struct proc *parent)
{
	struct list_head *pos, *n;

	if (!parent)
		return;

	spinlock_acquire(&parent->lock);
	list_for_each_safe(pos, n, &parent->children) {
		struct proc *child = list_entry(pos, struct proc, sibling);

		if (!child->vm_shared || child->state != PROC_ZOMBIE)
			continue;

		child->parent = NULL;
		list_del(&child->sibling);
		INIT_LIST_HEAD(&child->sibling);
		spinlock_release(&parent->lock);
		free_proc(child);
		spinlock_acquire(&parent->lock);
	}
	spinlock_release(&parent->lock);
}

