static int install_file_for_proc(struct proc *p, struct file *f)
{
	int fd;

	if (p->fd_table && p->fd_table->open_fds >= p->nofile_cur)
		return -EMFILE;

	fd = fd_alloc(p->fd_table);
	if (fd < 0)
		return -EMFILE;
	if ((u64)fd >= p->nofile_cur) {
		fd_free(p->fd_table, fd);
		return -EMFILE;
	}
	if (fd_install(p->fd_table, fd, f) < 0)
		return -EBADF;
	return fd;
}

static bool proc_fd_limit_exhausted(struct proc *p)
{
	return p->fd_table && p->fd_table->open_fds >= p->nofile_cur;
}

