/* 单个描述符结构体 */
struct virtq_desc {
	u64 addr;  /* 物理地址 */
	le32 len;  /* 数据长度 */
	u16 flags; /* 标志位 */
	u16 next;  /* 下一个描述符索引（如果 VRING_DESC_F_NEXT 置位） */
};
#define VRING_DESC_F_NEXT 1  /* 链接到另一个描述符 */
