	le16 csum_offset;
};

/* 可用环结构体 */
struct virtq_avail {
	u16 flags;  /* 标志位（始终为零） */
	u16 idx;    /* 驱动程序下一个写入的 ring 索引 */
	u16 ring[]; /* 链头描述符编号 */
};

/* 已用环条目结构体
 * 设备通过此结构体通知驱动程序已完成请求。
 */
struct virtq_used_elem {
	le32 id;  /* 已完成描述符链的起始索引 */
	le32 len; /* 已处理数据的长度 */
};

/* 已用环结构体 */
struct virtq_used {
	u16 flags;		       /* 标志位（始终为零） */
	u16 idx;		       /* 设备添加 ring[] 条目时递增 */
	struct virtq_used_elem ring[]; /* 已用环条目数组 */
};

