#define VIRTIO_BLK_T_OUT 1 /* 写入磁盘 */

/* 块设备请求结构体
 * 磁盘请求中第一个描述符的格式。
 * 后跟两个包含数据块和一个状态字节的描述符。
 */
struct virtio_blk_req {
	le32 type;     /* 请求类型：VIRTIO_BLK_T_IN 或 VIRTIO_BLK_T_OUT */
	le32 reserved; /* 保留字段 */
	u64 sector;    /* 扇区号 */
};

