/* ============================================================
 * I/O: read / write
 * ============================================================ */

uintptr_t sys_write(int fd, uintptr_t buf, size_t len)
{
	struct proc *p = curproc();
	size_t done = 0;

	if (len == 0)
		return 0;

	/* 即使 fd==1/2，如果已被 dup 重定向到真实文件则走 file_write */
	if (fd == 1 || fd == 2) {
		struct file *f = fd_get(p->fd_table, fd);
		if (f) {
			char tmp[512];
			while (done < len) {
				size_t n = len - done;
				if (n > sizeof(tmp))
					n = sizeof(tmp);
				if (copyin(p->pagetable, tmp, buf + done, n) < 0) {
					file_put(f);
					return done > 0 ? done : -EFAULT;
				}
				ssize_t ret = file_write(f, tmp, n);
				if (ret < 0) {
					file_put(f);
					return done > 0 ? done : ret;
				}
				done += (size_t)ret;
				if ((size_t)ret < n) {
					file_put(f);
					return done;
				}
			}
			file_put(f);
			return done;
		}

		while (done < len) {
				char tmp[512];
				size_t n = len - done;
				if (n > sizeof(tmp))
				n = sizeof(tmp);
			if (copyin(p->pagetable, tmp, buf + done, n) < 0)
				return done > 0 ? done : -EFAULT;
			for (size_t i = 0; i < n; i++)
				sbi_console_putchar(tmp[i]);
			done += n;
		}
		return done;
	}

	/* file fd */
	struct file *f = fd_get(p->fd_table, fd);
	if (!f)
		return -EBADF;

	char *tmp = kmalloc(USER_IO_CHUNK);
	if (!tmp) {
		file_put(f);
		return -ENOMEM;
	}
	while (done < len) {
		size_t n = len - done;
		if (n > USER_IO_CHUNK)
			n = USER_IO_CHUNK;

		if (copyin(p->pagetable, tmp, buf + done, n) < 0) {
			kfree(tmp);
			file_put(f);
			return done > 0 ? done : -EFAULT;
		}

		ssize_t ret = file_write(f, tmp, n);
		if (ret < 0) {
			kfree(tmp);
			file_put(f);
			return done > 0 ? done : ret;
		}
		done += (size_t)ret;
		if ((size_t)ret < n) {
			kfree(tmp);
			file_put(f);
			return done;
		}
	}

struct super_block *ext4_mount(struct file_system_type *fs_type,
			       dev_t dev, void *data)
{
	struct super_block *sb = super_alloc(fs_type, dev);
	if (IS_ERR(sb))
		return sb;

	sb->s_op = &ext4_super_ops;

	int ret = ext4_fill_super(sb, dev, data);
	if (ret < 0) {
		super_free(sb);
		return PTR(ret);
	}

	/* Read root inode (inode 2 is always the root directory in ext4) */
	struct inode *root_inode = inode_alloc(sb);
	if (!root_inode) {
		ext4_put_super(sb);
		super_free(sb);
		return PTR(-ENOMEM);
	}
	root_inode->i_ino = 2;  /* EXT4_ROOT_INO */

	ret = ext4_read_inode(sb, root_inode);
	if (ret < 0) {
		inode_free(root_inode);
		ext4_put_super(sb);
		super_free(sb);
		return PTR(ret);
	}

	root_inode->i_sb  = sb;
	root_inode->i_op  = &ext4_dir_inode_ops;
	root_inode->i_fop = &ext4_dir_operations;

	/* Create root dentry */
	struct dentry *root_dentry = dentry_root(sb);
	if (IS_ERR(root_dentry)) {
		int err = PTR_ERR(root_dentry);
		inode_free(root_inode);
		ext4_put_super(sb);
		super_free(sb);
		return PTR(err);
	}
	root_dentry->d_inode = root_inode;
	sb->s_root = root_dentry;

	return sb;
}

void ext4_kill_sb(struct super_block *sb)
{
	ext4_put_super(sb);
	if (sb->s_root) {
		dentry_free(sb->s_root);
		sb->s_root = NULL;
	}
}

/* Filesystem type registration */
static struct file_system_type ext4_fs_type = {
	.name    = "ext4",
	.mount   = ext4_mount,
	.kill_sb = ext4_kill_sb,
};

int ext4_init_fs(void)
{
	int ret = register_filesystem(&ext4_fs_type);
	if (ret < 0) {
		panic("ext4: failed to register filesystem");
		return ret;
	}
	return 0;
}

void syscall(void)
{
	struct proc *p = curproc();
	uintptr_t a0 = p->tf->a0;
	uintptr_t a1 = p->tf->a1;
	uintptr_t a2 = p->tf->a2;
	uintptr_t a3 = p->tf->a3;
	uintptr_t a4 = p->tf->a4;
	uintptr_t a5 = p->tf->a5;
	uintptr_t n = p->tf->a7;

	if (p->tgid >= 7700 && p->pid != p->tgid &&
	    child_syscall_debug_budget > 0) {
		infof("child-syscall: pid=%d tgid=%d nr=%ld epc=%p sp=%p tp=%p a0=%p a1=%p a2=%p",
		      p->pid, p->tgid, n, p->tf->epc, p->tf->sp, p->tf->tp,
		      a0, a1, a2);
		child_syscall_debug_budget--;
	}

	syscall_fn_t fn = syscall_lookup((int)n);
	if (!fn) {
		warnf("Unknown syscall %ld from pid %d", n, p->pid);
		p->tf->a0 = (uintptr_t)-ENOSYS;
		return;
	}

	p->tf->a0 = fn(a0, a1, a2, a3, a4, a5);
}

